     if (completedCount > 0 || completedCount < totalCount) {
         setShowToast(true);
         const timer = setTimeout(() => setShowToast(false), 1500);
         return () => clearTimeout(timer);
     }
  }, [completedCount]);

  // Determine Next Unlock
  const nextAchievement = state.achievements
    .filter(a => !a.unlockedAt)
    .sort((a, b) => {
        // Calculate closeness
        const getProgress = (type: string) => {
            if (type === 'streak') return stats.currentStreak;
            if (type === 'total_logs') return stats.totalLoggedDays;
            if (type === 'perfect_days') return stats.perfectDays;
            return 0;
        };
        const pA = getProgress(a.type) / a.targetValue;
        const pB = getProgress(b.type) / b.targetValue;
        return pB - pA; // Descending (highest progress first)
    })[0];

    const getProgressValue = (type: string) => {
        if (type === 'streak') return stats.currentStreak;
        if (type === 'total_logs') return stats.totalLoggedDays;
        if (type === 'perfect_days') return stats.perfectDays;
        return 0;
    };

