import React from 'react';
import { useApp } from '../context/AppContext';
import { Lock, Unlock } from 'lucide-react';

export const Progress: React.FC = () => {
  const { state, stats } = useApp();

  // --- WEEK DATA PREP ---
  const today = new Date();
  const weekData = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(today);
    d.setDate(d.getDate() - (6 - i));
    const dateStr = d.toISOString().split('T')[0];
    const dayName = d.toLocaleDateString('en-US', { weekday: 'narrow' });

    const log = state.logs.find(l => l.date === dateStr);
    const completed = log?.completedHabitIds.length || 0;
    const activeAtTime = state.habits.filter(h => h.isActive).length || 1; // Simplify for MVP
    const score = Math.min(completed / activeAtTime, 1);

    return { dayName, score, isToday: i === 6 };
  });

  // --- MONTH DATA PREP ---
  const monthDays = Array.from({ length: 30 }, (_, i) => {
    const d = new Date(today);
    d.setDate(d.getDate() - (29 - i));
    return d.toISOString().split('T')[0];
  });

  const getDayScore = (date: string) => {
    const log = state.logs.find(l => l.date === date);
    const activeCount = state.habits.filter(h => h.isActive).length || 1;
    if (!log) return 0;
    return Math.min(log.completedHabitIds.length / activeCount, 1);
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">Progress</h1>
      </header>

      {/* SECTION 1: WEEKLY DASHBOARD */}
      <section className="mb-8">
        <div className="flex items-end justify-between mb-4">
             <h3 className="text-xs font-semibold text-ledger-muted uppercase tracking-wider">This Week</h3>
             <span className="text-lg font-bold text-ledger-text dark:text-ledger-textDark">
                {Math.round(stats.weeklyScore * 100)}%
             </span>
        </div>

        <div className="bg-white dark:bg-ledger-surfaceDark p-6 rounded-xl border border-ledger-border dark:border-ledger-borderDark shadow-sm">
            <div className="flex justify-between items-end h-32">
                {weekData.map((d, i) => (
                    <div key={i} className="flex flex-col items-center gap-2 group w-full">
                         <div className="relative w-full flex justify-center h-full items-end">
                            <div 
                                className={`w-2 rounded-full transition-all duration-500 ${d.isToday ? 'bg-ledger-accent' : 'bg-ledger-accent/40 dark:bg-ledger-accent/30'}`}
                                style={{ height: `${Math.max(d.score * 100, 4)}%` }} // Min height for visibility
                            />
                         </div>
                         <span className={`text-[10px] font-medium ${d.isToday ? 'text-ledger-text dark:text-ledger-textDark' : 'text-ledger-muted'}`}>
                            {d.dayName}
                         </span>
                    </div>
                ))}
            </div>
        </div>
      </section>

      {/* SECTION 2: CONSISTENCY HEATMAP */}
      <section className="mb-8">
        <h3 className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mb-4">Consistency (30 Days)</h3>
        <div className="grid grid-cols-10 gap-1.5">
            {monthDays.map((date) => {
                const score = getDayScore(date);
                let bgColor = 'bg-gray-200 dark:bg-[#262626]';
                if (score === 1) bgColor = 'bg-ledger-accent';
                else if (score > 0) bgColor = 'bg-ledger-accent opacity-50';

                return (
                    <div
                        key={date}
                        className={`aspect-square rounded-[2px] ${bgColor}`}
                        title={date}
                    />
                );
            })}
        </div>
      </section>

      {/* SECTION 3: ACHIEVEMENTS */}
      <section className="mb-8">
         <div className="flex items-center justify-between mb-4">
            <h3 className="text-xs font-semibold text-ledger-muted uppercase tracking-wider">Achievements</h3>
            <span className="text-xs font-medium text-ledger-muted">
                {state.achievements.filter(a => a.unlockedAt).length} / {state.achievements.length}
            </span>
         </div>

         <div className="space-y-3">
             {state.achievements.map(ach => {
                 const isUnlocked = !!ach.unlockedAt;

                 // Calculate progress for locked items
                 let progress = 0;
                 if (!isUnlocked) {
                    if (ach.type === 'streak') progress = stats.currentStreak;
                    if (ach.type === 'total_logs') progress = stats.totalLoggedDays;
                    if (ach.type === 'perfect_days') progress = stats.perfectDays;
                 }

                 return (
                     <div key={ach.id} className={`flex items-center gap-4 p-4 rounded-xl border transition-colors ${isUnlocked ? 'bg-white dark:bg-ledger-surfaceDark border-ledger-border dark:border-ledger-borderDark' : 'bg-transparent border-transparent opacity-60'}`}>
                         <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 ${isUnlocked ? 'bg-ledger-accent/10 text-ledger-accent' : 'bg-gray-100 dark:bg-gray-800 text-ledger-muted'}`}>
                             {isUnlocked ? <Unlock size={18} /> : <Lock size={18} />}
                         </div>
                         <div className="flex-1">
                             <div className="flex justify-between items-start">
                                 <h4 className={`text-sm font-semibold ${isUnlocked ? 'text-ledger-text dark:text-ledger-textDark' : 'text-ledger-muted'}`}>{ach.title}</h4>
                                 {isUnlocked && (
                                     <span className="text-[10px] text-ledger-muted uppercase tracking-wide">
                                         {new Date(ach.unlockedAt!).toLocaleDateString(undefined, { month: 'short', day: 'numeric'})}
                                     </span>
                                 )}
                             </div>
                             <p className="text-xs text-ledger-muted mt-0.5">{ach.description}</p>

                             {!isUnlocked && (
                                 <div className="mt-2 flex items-center gap-2">
                                     <div className="flex-1 h-1 bg-gray-200 dark:bg-gray-800 rounded-full overflow-hidden">
                                         <div className="h-full bg-ledger-muted transition-all" style={{ width: `${Math.min((progress / ach.targetValue) * 100, 100)}%` }} />
                                     </div>
                                     <span className="text-[10px] font-medium text-ledger-muted">
                                         {progress}/{ach.targetValue}
                                     </span>
                                 </div>
                             )}
                         </div>
                     </div>
                 );
             })}
         </div>
      </section>

    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { MAX_HABITS } from '../types';
import { Trash2, Archive, ArrowUp, ArrowDown, RotateCcw, Plus, Activity } from 'lucide-react';
import { Button } from '../components/Button';

export const Habits: React.FC = () => {
  const { state, addHabit, updateHabitName, archiveHabit, restoreHabit, reorderHabits, stats } = useApp();
  const [newHabitName, setNewHabitName] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  const activeHabits = state.habits.filter(h => h.isActive);
  const archivedHabits = state.habits.filter(h => !h.isActive);
  const isLimitReached = activeHabits.length >= MAX_HABITS;

  const handleAdd = () => {
    if (!newHabitName.trim()) return;
    addHabit(newHabitName.trim());
    setNewHabitName('');
    setIsAdding(false);
  };

  const moveHabit = (index: number, direction: 'up' | 'down') => {
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex >= 0 && newIndex < activeHabits.length) {
        reorderHabits(index, newIndex);
    }
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6 overflow-y-auto">
      <header className="mb-6 flex justify-between items-center">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">Habits</h1>
        <span className="text-sm font-medium text-ledger-muted bg-gray-200 dark:bg-gray-800 px-2 py-1 rounded">
            {activeHabits.length} / {MAX_HABITS}
        </span>
      </header>

      {/* Active List */}
      <div className="space-y-4 mb-8">
        {activeHabits.map((habit, index) => {
          const consistency = stats.getHabitConsistency(habit.id);

          return (
            <div key={habit.id} className="bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl shadow-sm border border-ledger-border dark:border-ledger-borderDark flex flex-col gap-3 group">
              <div className="flex items-center justify-between">
                <div className="flex-1">
                    <input 
                        className="w-full bg-transparent font-medium text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-b border-ledger-accent"
                        value={habit.name}
                        onChange={(e) => updateHabitName(habit.id, e.target.value)}
                    />
                </div>
                <div className="flex items-center gap-1 ml-4 opacity-50 group-hover:opacity-100 transition-opacity">
                    <div className="flex flex-col mr-2">
                        <button 
                            onClick={() => moveHabit(index, 'up')}
                            disabled={index === 0}
                            className="p-1 hover:text-ledger-accent disabled:opacity-20"
                        >
                            <ArrowUp size={14} />
                        </button>
                        <button 
                            onClick={() => moveHabit(index, 'down')}
                            disabled={index === activeHabits.length - 1}
                            className="p-1 hover:text-ledger-accent disabled:opacity-20"
                        >
                            <ArrowDown size={14} />
                        </button>
                    </div>
                    <button 
                        onClick={() => archiveHabit(habit.id)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded text-ledger-muted hover:text-red-500"
                        title="Archive"
                    >
                        <Archive size={18} />
                    </button>
                </div>
              </div>

              {/* Consistency Micro-stat */}
              <div className="flex items-center gap-2 pt-2 border-t border-gray-50 dark:border-gray-800">
                  <Activity size={12} className="text-ledger-muted" />
                  <span className="text-[10px] uppercase font-semibold text-ledger-muted tracking-wide">
                    7-Day Consistency: <span className="text-ledger-accent">{Math.round(consistency)}%</span>
                  </span>
              </div>
            </div>
          );
        })}

        {isAdding ? (
            <div className="flex items-center gap-2 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-accent animate-fade-in">
                <input 
                    autoFocus
                    value={newHabitName}
                    onChange={e => setNewHabitName(e.target.value)}
                    placeholder="Habit name..."
                    className="flex-1 bg-transparent focus:outline-none text-ledger-text dark:text-ledger-textDark"
                    onKeyDown={e => e.key === 'Enter' && handleAdd()}
                />
                <button onClick={handleAdd} className="text-sm font-semibold text-ledger-accent">Save</button>
            </div>
        ) : (
             <Button 
                variant="secondary" 
                fullWidth 
                onClick={() => setIsAdding(true)}
                disabled={isLimitReached}
                className="border-dashed"
            >
                <Plus size={18} className="mr-2" />
                {isLimitReached ? 'Limit reached' : 'Add habit'}
            </Button>
        )}
      </div>

      {/* Archived Section */}
      {archivedHabits.length > 0 && (
        <div className="mt-auto pt-8">
            <h3 className="text-xs font-semibold uppercase text-ledger-muted tracking-wider mb-4">Archived</h3>
            <div className="space-y-2">
                {archivedHabits.map(habit => (
                    <div key={habit.id} className="flex items-center justify-between p-3 rounded-lg border border-transparent hover:border-ledger-border dark:hover:border-ledger-borderDark transition-colors">
                        <span className="text-ledger-muted line-through">{habit.name}</span>
                        <button 
                            onClick={() => restoreHabit(habit.id)}
                            disabled={isLimitReached}
                            className="p-2 text-ledger-accent hover:bg-green-50 dark:hover:bg-green-900/10 rounded flex items-center gap-1 text-sm disabled:opacity-30"
                        >
                            <RotateCcw size={14} />
                            Restore
                        </button>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

