import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, MAX_HABITS, STATIC_ACHIEVEMENTS, Achievement } from '../types';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => void;
  toggleHabit: (habitId: string, date: string) => void;
  updateHabitName: (id: string, name: string) => void;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  completeOnboarding: () => void;
  toggleTheme: () => void;
  resetData: () => void;
  exportData: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  lastTokenReset: new Date().toISOString().split('T')[0]
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('ledger_app_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migrations
      if (!parsed.achievements || parsed.achievements.length === 0) {
        parsed.achievements = STATIC_ACHIEVEMENTS.map(a => ({ ...a }));
      }
      if (parsed.repairTokens === undefined) {
        parsed.repairTokens = 3;
        parsed.lastTokenReset = new Date().toISOString().split('T')[0];
      }
      return parsed;
    }
    return defaultState;
  });

  // --- REPAIR TOKEN RESET LOGIC ---
  useEffect(() => {
    const today = new Date();
    const todayStr = today.toISOString().split('T')[0];

    // Check if we need to reset tokens (Sunday is start of week)
    const lastResetDate = new Date(state.lastTokenReset);

    // Simple logic: if today is Sunday and last reset was BEFORE today, reset.
    // Or if last reset was more than 7 days ago.
    // Better logic: Calculate the "Week Start" of Today and "Week Start" of Last Reset.
    const getWeekStart = (d: Date) => {
        const date = new Date(d);
        const day = date.getDay(); 
        const diff = date.getDate() - day; // Sunday
        return new Date(date.setDate(diff)).toISOString().split('T')[0];
    };

    const currentWeekStart = getWeekStart(today);
    const lastResetWeekStart = getWeekStart(lastResetDate);

    if (currentWeekStart > lastResetWeekStart) {
        // New week started
        setState(prev => ({
            ...prev,
            repairTokens: 3,
            lastTokenReset: todayStr
        }));
    }
  }, [state.lastTokenReset]);

  // --- STATS CALCULATION ---
  const calculateStats = () => {
    const todayStr = new Date().toISOString().split('T')[0];
    const activeHabitCount = state.habits.filter(h => h.isActive).length;

    // 1. Total Logged Days
    const totalLoggedDays = state.logs.length;

    // 2. Perfect Days
    const perfectDays = state.logs.filter(log => {
      if (activeHabitCount === 0) return false;
      return log.completedHabitIds.length >= activeHabitCount;
    }).length;

    // 3. Current Streak
    let currentStreak = 0;
    const sortedLogs = [...state.logs].sort((a, b) => b.date.localeCompare(a.date));

    if (sortedLogs.length > 0) {
      const lastLogDate = new Date(sortedLogs[0].date);
      const todayDate = new Date(todayStr);
      const diffTime = Math.abs(todayDate.getTime() - lastLogDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

      if (diffDays <= 1) {
        currentStreak = 1;
        let prevDate = lastLogDate;

        for (let i = 1; i < sortedLogs.length; i++) {
          const currentDate = new Date(sortedLogs[i].date);
          const gap = Math.abs(prevDate.getTime() - currentDate.getTime());
          const gapDays = Math.round(gap / (1000 * 60 * 60 * 24));

          if (gapDays === 1) {
            currentStreak++;
            prevDate = currentDate;
          } else {
            break;
          }
        }
      }
    }

    // 4. Weekly Score
    const oneWeekAgo = new Date();
    oneWeekAgo.setDate(oneWeekAgo.getDate() - 6);
    const oneWeekAgoStr = oneWeekAgo.toISOString().split('T')[0];

    const logsLast7Days = state.logs.filter(l => l.date >= oneWeekAgoStr && l.date <= todayStr);
    const totalCompletedLast7 = logsLast7Days.reduce((acc, log) => acc + log.completedHabitIds.length, 0);
    const potentialTotal = (activeHabitCount || 1) * 7; 
    const weeklyScore = totalCompletedLast7 / potentialTotal;

    return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const stats = {
    ...calculateStats(),
    getHabitConsistency: (habitId: string) => {
        const oneWeekAgo = new Date();
        oneWeekAgo.setDate(oneWeekAgo.getDate() - 6);
        const oneWeekAgoStr = oneWeekAgo.toISOString().split('T')[0];
        const todayStr = new Date().toISOString().split('T')[0];

        const relevantLogs = state.logs.filter(l => l.date >= oneWeekAgoStr && l.date <= todayStr);
        const count = relevantLogs.filter(l => l.completedHabitIds.includes(habitId)).length;
        return (count / 7) * 100;
    }
  };

  // --- ACHIEVEMENT WATCHER ---
  useEffect(() => {
    let hasChanges = false;
    const newAchievements = state.achievements.map(ach => {
      if (ach.unlockedAt) return ach; // Already unlocked

      let isUnlocked = false;
      if (ach.type === 'streak' && stats.currentStreak >= ach.targetValue) isUnlocked = true;
      if (ach.type === 'total_logs' && stats.totalLoggedDays >= ach.targetValue) isUnlocked = true;
      if (ach.type === 'perfect_days' && stats.perfectDays >= ach.targetValue) isUnlocked = true;

      if (isUnlocked) {
        hasChanges = true;
        return { ...ach, unlockedAt: new Date().toISOString() };
      }
      return ach;
    });

    if (hasChanges) {
      setState(prev => ({ ...prev, achievements: newAchievements }));
    }
  }, [state.logs, state.habits]);

  // Persistence
  useEffect(() => {
    localStorage.setItem('ledger_app_data', JSON.stringify(state));
    if (state.theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [state]);

  const addHabit = (name: string) => {
    if (state.habits.filter(h => h.isActive).length >= MAX_HABITS) return;

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      name,
      isActive: true,
      sortOrder: state.habits.length
    };

    setState(prev => ({
      ...prev,
      habits: [...prev.habits, newHabit]
    }));
  };

  const toggleHabit = (habitId: string, date: string) => {
    const todayStr = new Date().toISOString().split('T')[0];
    const isPast = date < todayStr;
    const isToday = date === todayStr;

    // Strict rule: No future logging
    if (date > todayStr) return;

    // Strict rule: Repair logic
    // We only allow repair if it is within the current week (Sun-Sat)
    const targetDate = new Date(date);
    const todayDate = new Date(todayStr);
    const dayDiff = Math.floor((todayDate.getTime() - targetDate.getTime()) / (1000 * 60 * 60 * 24));

    // Assuming we only allow repair for last 6 days maximum to keep it within reason, 
    // strictly speaking the requirement is "same week". 
    // Calculating "Same Week":
    const currentWeekStart = new Date(todayDate);
    currentWeekStart.setDate(todayDate.getDate() - todayDate.getDay());
    const targetWeekStart = new Date(targetDate);
    targetWeekStart.setDate(targetDate.getDate() - targetDate.getDay());

    const isDifferentWeek = currentWeekStart.getTime() !== targetWeekStart.getTime();

    if (isPast && isDifferentWeek) {
        // Read-only for past weeks
        alert("Past weeks are locked.");
        return;
    }

    setState(prev => {
      const existingLogIndex = prev.logs.findIndex(l => l.date === date);
      let newLogs = [...prev.logs];
      let newTokens = prev.repairTokens;

      if (existingLogIndex >= 0) {
        const log = newLogs[existingLogIndex];
        const isCompleted = log.completedHabitIds.includes(habitId);

        let newCompletedIds;
        let newRepairedIds = log.repairedHabitIds || [];

        if (isCompleted) {
          // Unchecking
          newCompletedIds = log.completedHabitIds.filter(id => id !== habitId);
          newRepairedIds = newRepairedIds.filter(id => id !== habitId);
          // Note: No token refund
        } else {
          // Checking
          if (isPast) {
             if (newTokens > 0) {
                 newTokens -= 1;
                 newCompletedIds = [...log.completedHabitIds, habitId];
                 newRepairedIds = [...newRepairedIds, habitId];
             } else {
                 alert("No repair tokens remaining for this week.");
                 return prev;
             }
          } else {
             newCompletedIds = [...log.completedHabitIds, habitId];
          }
        }

        newLogs[existingLogIndex] = { 
            ...log, 
            completedHabitIds: newCompletedIds,
            repairedHabitIds: newRepairedIds
        };
      } else {
        // Create new log
        if (isPast) {
            if (newTokens > 0) {
                newTokens -= 1;
                newLogs.push({
                    date,
                    completedHabitIds: [habitId],
                    repairedHabitIds: [habitId]
                });
            } else {
                alert("No repair tokens remaining for this week.");
                return prev;
            }
        } else {
            newLogs.push({
                date,
                completedHabitIds: [habitId],
                repairedHabitIds: []
            });
        }
      }

      return { ...prev, logs: newLogs, repairTokens: newTokens };
    });
  };

  const updateHabitName = (id: string, name: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, name } : h)
    }));
  };

  const archiveHabit = (id: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, isActive: false } : h)
    }));
  };

  const restoreHabit = (id: string) => {
    if (state.habits.filter(h => h.isActive).length >= MAX_HABITS) return;
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, isActive: true } : h)
    }));
  };

  const reorderHabits = (fromIndex: number, toIndex: number) => {
    setState(prev => {
      const activeHabits = prev.habits.filter(h => h.isActive);
      const archivedHabits = prev.habits.filter(h => !h.isActive);

      const newActive = [...activeHabits];
      const [moved] = newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);

      return { ...prev, habits: [...newActive, ...archivedHabits] };
    });
  };

  const completeOnboarding = () => {
    setState(prev => ({ ...prev, isOnboarded: true }));
  };

  const toggleTheme = () => {
    setState(prev => ({ ...prev, theme: prev.theme === 'light' ? 'dark' : 'light' }));
  };

  const resetData = () => {
    if(confirm("Delete all data? This cannot be undone.")) {
        setState(defaultState);
        window.location.reload();
    }
  };

  const exportData = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "ledger_export.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <AppContext.Provider value={{ 
      state, addHabit, toggleHabit, updateHabitName, archiveHabit, 
      restoreHabit, reorderHabits, completeOnboarding, toggleTheme, resetData, exportData,
      stats
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ProgressRing } from '../components/ProgressRing';
import { User, Check, AlertCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Today: React.FC = () => {
  const { state, toggleHabit } = useApp();
  const navigate = useNavigate();

  // --- DATE MATH ---
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const dayOfWeek = today.getDay(); // 0 = Sun, 6 = Sat

  // Calculate Start of Week (Sunday)
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  // Calculate End of Week (Saturday)
  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  // Generate Array of 7 days for the header
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    return {
        dateStr: d.toISOString().split('T')[0],
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: d.toISOString().split('T')[0] === todayStr,
        isFuture: d.toISOString().split('T')[0] > todayStr
    };
  });

  const activeHabits = state.habits.filter(h => h.isActive);

  // Weekly Score Calculation
  const weekLogs = state.logs.filter(l => l.date >= weekDays[0].dateStr && l.date <= weekDays[6].dateStr);
  const totalCompleted = weekLogs.reduce((acc, log) => acc + log.completedHabitIds.length, 0);
  const totalPotential = Math.max(activeHabits.length * 7, 1);
  const weeklyPercentage = (totalCompleted / totalPotential) * 100;

  const handleToggle = (id: string, date: string, isFuture: boolean) => {
    if (isFuture) return;
    toggleHabit(id, date);
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative">
      {/* Header */}
      <header className="px-6 py-4 flex items-center justify-between sticky top-0 z-10 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-md border-b border-transparent">
        <div>
            <h1 className="text-sm font-bold text-ledger-text dark:text-ledger-textDark uppercase tracking-wide">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </h1>
            <div className="flex items-center gap-1.5 mt-1">
                <span className="text-xs text-ledger-muted font-medium">
                    Repairs: {state.repairTokens} left
                </span>
            </div>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark opacity-60 hover:opacity-100 transition-opacity">
          <User size={20} />
        </button>
      </header>

      {/* Weekly Score Hero (Compact) */}
      <div className="px-6 py-4 flex items-center gap-6 border-b border-ledger-border dark:border-ledger-borderDark">
         <div className="w-16 h-16 shrink-0">
             <ProgressRing radius={32} stroke={4} progress={weeklyPercentage} />
         </div>
         <div>
             <div className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">
                 {Math.round(weeklyPercentage)}%
             </div>
             <div className="text-xs text-ledger-muted uppercase tracking-wide">
                 Weekly Completion
             </div>
             <div className="text-xs text-ledger-muted mt-1">
                 {totalCompleted} / {totalPotential} checks
             </div>
         </div>
      </div>

      {/* Main Grid */}
      <div className="flex-1 overflow-auto no-scrollbar pb-20">
         <div className="min-w-full">
             {/* Grid Header */}
             <div className="grid grid-cols-[1.5fr_repeat(7,1fr)] gap-2 px-4 py-3 sticky top-0 bg-ledger-bg dark:bg-ledger-bgDark z-0">
                 <div className="font-semibold text-xs text-ledger-muted uppercase self-end pb-1">Habit</div>
                 {weekDays.map(d => (
                     <div key={d.dateStr} className={`flex flex-col items-center gap-1 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                         <span className="text-[10px] font-bold uppercase">{d.label}</span>
                         <span className={`text-xs font-medium w-6 h-6 flex items-center justify-center rounded-full ${d.isToday ? 'bg-ledger-accent text-white' : ''}`}>
                             {d.dayNum}
                         </span>
                     </div>
                 ))}
             </div>

             {/* Grid Rows */}
             <div className="px-4 pb-4 space-y-1">
                 {activeHabits.map(habit => (
                     <div key={habit.id} className="grid grid-cols-[1.5fr_repeat(7,1fr)] gap-2 items-center min-h-[48px] border-b border-gray-100 dark:border-gray-800 last:border-0">
                         <div className="text-sm font-medium text-ledger-text dark:text-ledger-textDark truncate pr-2">
                             {habit.name}
                         </div>
                         {weekDays.map(d => {
                             const log = state.logs.find(l => l.date === d.dateStr);
                             const isCompleted = log?.completedHabitIds.includes(habit.id);
                             const isRepaired = log?.repairedHabitIds?.includes(habit.id);

                             // Styles
                             let cellContent = null;
                             let cellClass = "w-8 h-8 rounded-md flex items-center justify-center transition-all duration-200 border border-transparent";

                             if (d.isFuture) {
                                 cellClass += " bg-gray-50 dark:bg-white/5 opacity-50 cursor-not-allowed";
                             } else if (isCompleted) {
                                 if (isRepaired) {
                                    // Repaired style: Hollow or Dotted
                                    cellClass += " border-2 border-ledger-accent text-ledger-accent bg-transparent";
                                    cellContent = <div className="w-2 h-2 rounded-full bg-ledger-accent" />;
                                 } else {
                                     // Normal style: Solid
                                     cellClass += " bg-ledger-accent text-white shadow-sm";
                                     cellContent = <Check size={14} strokeWidth={3} />;
                                 }
                             } else {
                                 // Empty style
                                 cellClass += " bg-gray-100 dark:bg-ledger-surfaceDark hover:border-ledger-muted/30";
                             }

                             return (
                                 <button
                                    key={d.dateStr}
                                    onClick={() => handleToggle(habit.id, d.dateStr, d.isFuture)}
                                    disabled={d.isFuture}
                                    className="flex justify-center"
                                 >
                                     <div className={cellClass}>
                                         {cellContent}
                                     </div>
                                 </button>
                             );
                         })}
                     </div>
                 ))}
             </div>

             {activeHabits.length === 0 && (
                <div className="p-8 text-center text-ledger-muted">
                    No active habits. Go to Habits tab to add some.
                </div>
             )}
         </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { Lock, Unlock, ChevronDown } from 'lucide-react';

type Range = 'Year' | '6M' | 'Quarter' | 'Month';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [range, setRange] = useState<Range>('Quarter');

  // --- DATA PROCESSING ---
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];

  const getWeeksInRange = (r: Range) => {
    let weeks = 0;
    if (r === 'Year') weeks = 52;
    if (r === '6M') weeks = 26;
    if (r === 'Quarter') weeks = 13;
    if (r === 'Month') return 0; // Handled separately
    return weeks;
  };

  const calculateRangeStats = () => {
     let startDate = new Date(today);
     if (range === 'Month') startDate.setDate(startDate.getDate() - 30);
     else if (range === 'Quarter') startDate.setDate(startDate.getDate() - (13 * 7));
     else if (range === '6M') startDate.setDate(startDate.getDate() - (26 * 7));
     else startDate.setDate(startDate.getDate() - (52 * 7));

     const startDateStr = startDate.toISOString().split('T')[0];

     const relevantLogs = state.logs.filter(l => l.date >= startDateStr && l.date <= todayStr);

     // Potential (approximate)
     const days = Math.floor((today.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24));
     const activeHabits = Math.max(state.habits.filter(h => h.isActive).length, 1);
     const potentialChecks = days * activeHabits;

     const totalChecks = relevantLogs.reduce((acc, l) => acc + l.completedHabitIds.length, 0);
     const daysLogged = relevantLogs.length;
     const percentage = potentialChecks > 0 ? (totalChecks / potentialChecks) * 100 : 0;

     return { percentage, totalChecks, potentialChecks, daysLogged, daysTotal: days };
  };

  const stats = calculateRangeStats();

  // --- RENDER HELPERS ---
  const renderWeeklyHeatmap = () => {
      const weekCount = getWeeksInRange(range);
      // Generate weeks backwards
      const weeks = [];
      for(let i=0; i<weekCount; i++) {
          const wEnd = new Date(today);
          wEnd.setDate(wEnd.getDate() - (i * 7));
          const wStart = new Date(wEnd);
          wStart.setDate(wStart.getDate() - 6);

          const startStr = wStart.toISOString().split('T')[0];
          const endStr = wEnd.toISOString().split('T')[0];

          // Get logs
          const wLogs = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
          const checks = wLogs.reduce((acc, l) => acc + l.completedHabitIds.length, 0);
          const active = Math.max(state.habits.filter(h => h.isActive).length, 1);
          const potential = active * 7;
          const score = Math.min(checks / potential, 1);

          weeks.push({ score, label: wStart.getDate() });
      }

      return (
          <div className="flex flex-row-reverse gap-1 h-32 items-end justify-between px-2">
              {weeks.map((w, idx) => (
                  <div key={idx} className="flex flex-col items-center gap-1 flex-1 group">
                      <div className="w-full bg-gray-100 dark:bg-white/5 rounded-sm relative h-full flex items-end overflow-hidden">
                          <div 
                            className={`w-full transition-all duration-500 ${w.score === 1 ? 'bg-ledger-accent' : 'bg-ledger-accent/60'}`} 
                            style={{ height: `${Math.max(w.score * 100, 5)}%` }} 
                          />
                      </div>
                      {/* Show label every 4 weeks */}
                      {idx % 4 === 0 && (
                          <span className="text-[9px] text-ledger-muted">{w.label}</span>
                      )}
                  </div>
              ))}
          </div>
      );
  };

  const renderDailyHeatmap = () => {
      const days = [];
      for(let i=29; i>=0; i--) {
          const d = new Date(today);
          d.setDate(d.getDate() - i);
          const dStr = d.toISOString().split('T')[0];
          const log = state.logs.find(l => l.date === dStr);
          const checks = log?.completedHabitIds.length || 0;
          const active = Math.max(state.habits.filter(h => h.isActive).length, 1);
          const score = Math.min(checks / active, 1);
          days.push({ date: dStr, score });
      }

      return (
          <div className="grid grid-cols-7 gap-2">
              {days.map(d => (
                  <div 
                    key={d.date} 
                    className={`aspect-square rounded-sm transition-all ${d.score === 0 ? 'bg-gray-100 dark:bg-white/5' : d.score === 1 ? 'bg-ledger-accent' : 'bg-ledger-accent/50'}`} 
                  />
              ))}
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6 overflow-y-auto no-scrollbar">
      <header className="mb-6 flex justify-between items-center">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">Progress</h1>
      </header>

      {/* Range Selector */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-lg mb-8">
          {(['Year', '6M', 'Quarter', 'Month'] as Range[]).map(r => (
              <button 
                key={r}
                onClick={() => setRange(r)}
                className={`flex-1 py-1.5 text-xs font-semibold rounded-md transition-all ${range === r ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {r}
              </button>
          ))}
      </div>

      {/* Primary KPI Section */}
      <section className="mb-8">
          <div className="grid grid-cols-3 gap-4 mb-6">
              <div className="bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl border border-ledger-border dark:border-ledger-borderDark shadow-sm">
                  <div className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">{Math.round(stats.percentage)}%</div>
                  <div className="text-[10px] uppercase font-semibold text-ledger-muted mt-1">Completion</div>
              </div>
              <div className="bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl border border-ledger-border dark:border-ledger-borderDark shadow-sm">
                  <div className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">{stats.totalChecks}</div>
                  <div className="text-[10px] uppercase font-semibold text-ledger-muted mt-1">Total Checks</div>
              </div>
              <div className="bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl border border-ledger-border dark:border-ledger-borderDark shadow-sm">
                  <div className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">{stats.daysLogged}</div>
                  <div className="text-[10px] uppercase font-semibold text-ledger-muted mt-1">Days Logged</div>
              </div>
          </div>

          <div className="bg-white dark:bg-ledger-surfaceDark p-6 rounded-xl border border-ledger-border dark:border-ledger-borderDark shadow-sm">
              <h3 className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mb-6">Activity Map</h3>
              {range === 'Month' ? renderDailyHeatmap() : renderWeeklyHeatmap()}
          </div>
      </section>

      {/* Achievements Section */}
      <section className="mb-8">
         <div className="flex items-center justify-between mb-4">
            <h3 className="text-xs font-semibold text-ledger-muted uppercase tracking-wider">Achievements</h3>
            <span className="text-xs font-medium text-ledger-muted">
                {state.achievements.filter(a => a.unlockedAt).length} / {state.achievements.length}
            </span>
         </div>

         <div className="space-y-3">
             {state.achievements.map(ach => {
                 const isUnlocked = !!ach.unlockedAt;
                 return (
                     <div key={ach.id} className={`flex items-center gap-4 p-4 rounded-xl border transition-colors ${isUnlocked ? 'bg-white dark:bg-ledger-surfaceDark border-ledger-border dark:border-ledger-borderDark' : 'bg-transparent border-transparent opacity-60'}`}>
                         <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 ${isUnlocked ? 'bg-ledger-accent/10 text-ledger-accent' : 'bg-gray-100 dark:bg-gray-800 text-ledger-muted'}`}>
                             {isUnlocked ? <Unlock size={18} /> : <Lock size={18} />}
                         </div>
                         <div className="flex-1">
                             <div className="flex justify-between items-start">
                                 <h4 className={`text-sm font-semibold ${isUnlocked ? 'text-ledger-text dark:text-ledger-textDark' : 'text-ledger-muted'}`}>{ach.title}</h4>
                                 {isUnlocked && (
                                     <span className="text-[10px] text-ledger-muted uppercase tracking-wide">
                                         {new Date(ach.unlockedAt!).toLocaleDateString(undefined, { month: 'short', day: 'numeric'})}
                                     </span>
                                 )}
                             </div>
                             <p className="text-xs text-ledger-muted mt-0.5">{ach.description}</p>
                         </div>
                     </div>
                 );
             })}
         </div>
      </section>
    </div>
  );
};

