                        ${d.isToday ? 'ring-2 ring-ledger-accent ring-offset-1 dark:ring-offset-ledger-bgDark' : ''}
                    `}
                 >
                     {d.dayNum}
                 </div>
             ))}
        </div>
    );
  };

  // --- VIEW: WEEK (Chart) ---
  const renderWeekView = () => {
      // Calculate selected week range
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay();
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff); // This is Sunday of selected week

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];
          const log = state.logs.find(l => l.date === dateStr);

          const active = state.habits.filter(h => h.isActive).length || 1;
          const completed = log?.completedHabitIds.length || 0;
          const pct = Math.min((completed / active) * 100, 100);
          const isDifferentYear = d.getFullYear() !== currentYear;

          return { 
              label: d.toLocaleDateString('en-US', { weekday: 'narrow' }), 
              pct, 
              dateStr,
              isDifferentYear
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button onClick={() => setSelectedWeekOffset(p => p - 1)} className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full">
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button onClick={() => setSelectedWeekOffset(p => p + 1)} disabled={selectedWeekOffset >= 0} className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30">
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${Math.max(d.pct, 4)}%` }} // Min height for visibility
                              />
                          </div>
                          <span className="text-xs font-bold text-ledger-muted uppercase">{d.label}</span>
                      </div>
                  ))}
              </div>
              <p className="text-center text-[10px] text-ledger-muted mt-4">
                Gray columns indicate days outside the current year.
              </p>
          </div>
      );
  };

  // Helper
  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; // 0-indexed for array mapping
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-8 mx-2">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in">
          {view === 'Year' && (
              <div>
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
                  <p className="text-center text-[10px] text-ledger-muted mt-6">Each box represents a week. Fill level indicates active days.</p>
              </div>
          )}
          {view === 'Month' && (
              <div>
                  <h3 className="px-4 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{today.toLocaleDateString('en-US', { month: 'long', year: 'numeric'})}</h3>
                  {renderMonthView()}
              </div>
          )}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight } from 'lucide-react';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); // 0 = Current week

  const today = new Date();
  const currentYear = today.getFullYear();

  // Helper
  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; // 0-indexed for array mapping
  };

  const currentWeekIndex = getWeekNumber(today);

  // --- VIEW: YEAR (Water Fill) ---
  const renderYearView = () => {
    // Generate 53 weeks
    const weeks = [];
    let d = new Date(currentYear, 0, 1);

    // Adjust to first Sunday of the year or before
    while (d.getDay() !== 0) {
        d.setDate(d.getDate() - 1);
    }

    for (let i = 0; i < 53; i++) {
        const weekStart = new Date(d);
        const weekEnd = new Date(d);
        weekEnd.setDate(weekEnd.getDate() + 6);

        // Count days logged in this week
        const startStr = weekStart.toISOString().split('T')[0];
        const endStr = weekEnd.toISOString().split('T')[0];

        const logsInWeek = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
        // We count unique days logged, not total habits
        const daysLogged = new Set(logsInWeek.map(l => l.date)).size;
        const fillPercent = (daysLogged / 7) * 100;

        weeks.push({ 
            id: i, 
            fillPercent, 
            startDate: weekStart,
            isCurrent: i === currentWeekIndex 
        });

        // Advance 1 week
        d.setDate(d.getDate() + 7);
    }

    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {weeks.map((w) => (
                <button
                    key={w.id}
                    onClick={() => {
                        // Calculate offset from current week
                        const offset = w.id - currentWeekIndex;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border border-gray-200 dark:border-gray-800 relative overflow-hidden flex items-end ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}`}
                >
                    <div 
                        className="w-full bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                        style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                    />
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH (Calendar) ---
  const renderMonthView = () => {
    const daysInMonth = new Date(currentYear, today.getMonth() + 1, 0).getDate();
    const days = Array.from({ length: daysInMonth }, (_, i) => {
        const d = new Date(currentYear, today.getMonth(), i + 1);
        const dateStr = d.toISOString().split('T')[0];
        const hasLog = state.logs.some(l => l.date === dateStr && l.completedHabitIds.length > 0);
        return { dateStr, dayNum: i + 1, hasLog, isToday: dateStr === today.toISOString().split('T')[0] };
    });

    return (
        <div className="grid grid-cols-7 gap-3 px-4">
             {['S','M','T','W','T','F','S'].map((d,i) => (
                 <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase">{d}</div>
             ))}
             {days.map(d => (
                 <div 
                    key={d.dateStr}
                    className={`aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all
                        ${d.hasLog 
                            ? 'bg-ledger-accent text-white shadow-sm' 
                            : 'bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800'}
                        ${d.isToday ? 'ring-2 ring-ledger-accent ring-offset-1 dark:ring-offset-ledger-bgDark' : ''}
                    `}
                 >
                     {d.dayNum}
                 </div>
             ))}
        </div>
    );
  };

  // --- VIEW: WEEK (Chart) ---
  const renderWeekView = () => {
      // Calculate selected week range
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay();
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff); // This is Sunday of selected week

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];
          const log = state.logs.find(l => l.date === dateStr);

          const active = state.habits.filter(h => h.isActive).length || 1;
          const completed = log?.completedHabitIds.length || 0;
          const pct = Math.min((completed / active) * 100, 100);
          const isDifferentYear = d.getFullYear() !== currentYear;

          return { 
              label: d.toLocaleDateString('en-US', { weekday: 'narrow' }), 
              pct, 
              dateStr,
              isDifferentYear
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      // Prevent navigating before the first week of the year
      const isEarliestWeek = selectedWeekOffset <= -currentWeekIndex;

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${Math.max(d.pct, 4)}%` }} // Min height for visibility
                              />
                          </div>
                          <span className="text-xs font-bold text-ledger-muted uppercase">{d.label}</span>
                      </div>
                  ))}
              </div>
              <p className="text-center text-[10px] text-ledger-muted mt-4">
                Gray columns indicate days outside the current year.
              </p>
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-8 mx-2">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in">
          {view === 'Year' && (
              <div>
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
                  <p className="text-center text-[10px] text-ledger-muted mt-6">Each box represents a week. Fill level indicates active days.</p>
              </div>
          )}
          {view === 'Month' && (
              <div>
                  <h3 className="px-4 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{today.toLocaleDateString('en-US', { month: 'long', year: 'numeric'})}</h3>
                  {renderMonthView()}
              </div>
          )}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { User, Check, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Today: React.FC = () => {
  const { state, toggleHabit } = useApp();
  const navigate = useNavigate();
  const [expandedHabitId, setExpandedHabitId] = useState<string | null>(null);

  // --- DATE MATH ---
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const dayOfWeek = today.getDay(); // 0 = Sun, 6 = Sat

  // Calculate Start of Week (Sunday)
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  // Calculate End of Week (Saturday)
  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  // Generate Array of 7 days for the header
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    return {
        dateStr: d.toISOString().split('T')[0],
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: d.toISOString().split('T')[0] === todayStr,
        isFuture: d.toISOString().split('T')[0] > todayStr
    };
  });

  const activeHabits = state.habits.filter(h => h.isActive);

  // Weekly Score Calculation
  const weekLogs = state.logs.filter(l => l.date >= weekDays[0].dateStr && l.date <= weekDays[6].dateStr);
  const totalCompleted = weekLogs.reduce((acc, log) => acc + log.completedHabitIds.length, 0);
  const totalPotential = Math.max(activeHabits.length * 7, 1);
  const weeklyPercentage = (totalCompleted / totalPotential) * 100;

  const handleToggle = (id: string, date: string, isFuture: boolean) => {
    if (isFuture) return;
    toggleHabit(id, date);
  };

  const toggleExpand = (id: string) => {
      setExpandedHabitId(prev => prev === id ? null : id);
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative font-sans">
      {/* Header */}
      <header className="px-6 py-5 flex items-center justify-between sticky top-0 z-30 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl border-b border-ledger-border dark:border-ledger-borderDark">
        <div>
            <h1 className="text-base font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">
                Current Week
            </h1>
            <p className="text-xs text-ledger-muted mt-0.5 font-medium">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </p>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark hover:opacity-70 transition-opacity">
          <User size={22} strokeWidth={2} />
        </button>
      </header>

      {/* KPI Section */}
      <div className="px-6 py-6 border-b border-ledger-border dark:border-ledger-borderDark bg-white dark:bg-[#111111]">
         <div className="flex items-center justify-between">
             <div>
                <div className="text-4xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tight">
                    {Math.round(weeklyPercentage)}%
                </div>
                <div className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mt-1">Completion</div>
             </div>

             <div className="flex flex-col items-end gap-1">
                 <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 dark:bg-white/10 rounded-md">
                    <Zap size={14} className="text-ledger-accent" fill="currentColor" />
                    <span className="text-xs font-bold text-ledger-text dark:text-ledger-textDark">{state.repairTokens}</span>
                 </div>
                 <span className="text-[10px] font-medium text-ledger-muted">Repairs Left</span>
             </div>
         </div>
      </div>

      {/* Main Grid - Two Column Layout with Scroll */}
      <div className="flex-1 overflow-auto no-scrollbar pb-24 relative">
         <div className="inline-block min-w-full align-middle">
             {/* Sticky Header Row */}
             <div className="sticky top-0 z-20 flex border-b border-ledger-border dark:border-ledger-borderDark bg-ledger-bg dark:bg-ledger-bgDark shadow-sm">
                 {/* Left Column Header (Fixed) */}
                 <div className="sticky left-0 z-30 w-1/3 flex-none px-4 py-4 bg-ledger-bg dark:bg-ledger-bgDark border-r border-gray-100 dark:border-gray-800">
                     <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider">Task</span>
                 </div>

                 {/* Right Column Header (Scrollable content) */}
                 <div className="flex-1 flex min-w-max px-2">
                     {weekDays.map(d => (
                         <div key={d.dateStr} className={`w-14 flex flex-col items-center justify-center gap-1.5 py-4 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                             <span className="text-[10px] font-bold uppercase tracking-wider">{d.label}</span>
                             <span className={`text-xs font-bold w-6 h-6 flex items-center justify-center rounded-full transition-colors ${d.isToday ? 'bg-ledger-accent text-white shadow-md' : 'bg-transparent text-inherit'}`}>
                                 {d.dayNum}
                             </span>
                         </div>
                     ))}
                 </div>
             </div>

             {/* Rows */}
             <div className="divide-y divide-gray-100 dark:divide-gray-800/50">
                 {activeHabits.map(habit => {
                     const isExpanded = expandedHabitId === habit.id;
                     return (
                         <div key={habit.id} className="flex group bg-white dark:bg-ledger-bgDark">
                             {/* Left Column (Task Name - Fixed) */}
                             <button 
                                onClick={() => toggleExpand(habit.id)}
                                className={`sticky left-0 z-10 w-1/3 flex-none px-4 py-3 text-left border-r border-gray-100 dark:border-gray-800 bg-white dark:bg-ledger-bgDark transition-colors flex items-center ${isExpanded ? 'items-start' : 'items-center'}`}
                             >
                                 <span className={`text-sm font-semibold text-ledger-text dark:text-ledger-textDark transition-all duration-200 block ${isExpanded ? 'whitespace-normal' : 'truncate'}`}>
                                     {habit.name}
                                 </span>
                             </button>

                             {/* Right Column (Days - Scrollable) */}
                             <div className="flex-1 flex min-w-max px-2 items-center">
                                 {weekDays.map(d => {
                                     const log = state.logs.find(l => l.date === d.dateStr);
                                     const isCompleted = log?.completedHabitIds.includes(habit.id);
                                     const isRepaired = log?.repairedHabitIds?.includes(habit.id);

                                     // High Contrast Styles
                                     let cellContent = null;
                                     let cellClass = "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-200 border-2";

                                     if (d.isFuture) {
                                         cellClass += " border-transparent bg-gray-50 dark:bg-white/5 opacity-30 cursor-not-allowed";
                                     } else if (isCompleted) {
                                         if (isRepaired) {
                                            // Repaired
                                            cellClass += " border-ledger-accent text-ledger-accent bg-transparent";
                                            cellContent = <div className="w-3 h-3 rounded-full bg-ledger-accent" />;
                                         } else {
                                             // Normal
                                             cellClass += " border-ledger-accent bg-ledger-accent text-white shadow-sm";
                                             cellContent = <Check size={20} strokeWidth={4} />;
                                         }
                                     } else {
                                         // Empty
                                         cellClass += " border-gray-200 dark:border-gray-800 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent/50";
                                     }

                                     return (
                                         <div key={d.dateStr} className="w-14 flex justify-center py-2">
                                             <button
                                                onClick={() => handleToggle(habit.id, d.dateStr, d.isFuture)}
                                                disabled={d.isFuture}
                                                className="active:scale-95 transition-transform"
                                             >
                                                 <div className={cellClass}>
                                                     {cellContent}
                                                 </div>
                                             </button>
                                         </div>
                                     );
                                 })}
                             </div>
                         </div>
                     );
                 })}
             </div>

             {activeHabits.length === 0 && (
                <div className="p-8 text-center text-ledger-muted sticky left-0">
                    No active habits. Go to Habits tab to add some.
                </div>
             )}
         </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight } from 'lucide-react';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); // 0 = Current week
  const [selectedMonthOffset, setSelectedMonthOffset] = useState(0); // 0 = Current month

  const today = new Date();
  const currentYear = today.getFullYear();

  // Helper
  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; // 0-indexed for array mapping
  };

  const currentWeekIndex = getWeekNumber(today);

  // --- VIEW: YEAR (Water Fill) ---
  const renderYearView = () => {
    // Generate 53 weeks
    const weeks = [];
    let d = new Date(currentYear, 0, 1);

    // Adjust to first Sunday of the year or before
    while (d.getDay() !== 0) {
        d.setDate(d.getDate() - 1);
    }

    for (let i = 0; i < 53; i++) {
        const weekStart = new Date(d);
        const weekEnd = new Date(d);
        weekEnd.setDate(weekEnd.getDate() + 6);

        // Count days logged in this week
        const startStr = weekStart.toISOString().split('T')[0];
        const endStr = weekEnd.toISOString().split('T')[0];

        const logsInWeek = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
        // We count unique days logged, not total habits
        const daysLogged = new Set(logsInWeek.map(l => l.date)).size;
        const fillPercent = (daysLogged / 7) * 100;

        weeks.push({ 
            id: i, 
            fillPercent, 
            startDate: weekStart,
            isCurrent: i === currentWeekIndex 
        });

        // Advance 1 week
        d.setDate(d.getDate() + 7);
    }

    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {weeks.map((w) => (
                <button
                    key={w.id}
                    onClick={() => {
                        // Calculate offset from current week
                        const offset = w.id - currentWeekIndex;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border border-gray-200 dark:border-gray-800 relative overflow-hidden flex items-end ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}`}
                >
                    <div 
                        className="w-full bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                        style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                    />
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH (Calendar) ---
  const renderMonthView = () => {
    // Calculate Target Month
    const targetDate = new Date(today.getFullYear(), today.getMonth() + selectedMonthOffset, 1);
    const targetMonth = targetDate.getMonth();
    const targetYear = targetDate.getFullYear();

    // Limits: Cannot go before Jan 1st of current year, or after Dec 31st of current year
    const minOffset = -today.getMonth(); // Back to Jan
    const maxOffset = 11 - today.getMonth(); // Forward to Dec

    const isPrevDisabled = selectedMonthOffset <= minOffset;
    const isNextDisabled = selectedMonthOffset >= maxOffset;

    // Calendar Math
    const daysInMonth = new Date(targetYear, targetMonth + 1, 0).getDate();
    const firstDayIndex = new Date(targetYear, targetMonth, 1).getDay(); // 0 = Sunday

    // Generate Days
    const days = Array.from({ length: daysInMonth }, (_, i) => {
        const d = new Date(targetYear, targetMonth, i + 1);
        const dateStr = d.toISOString().split('T')[0];
        const hasLog = state.logs.some(l => l.date === dateStr && l.completedHabitIds.length > 0);
        const isToday = dateStr === today.toISOString().split('T')[0];
        return { dateStr, dayNum: i + 1, hasLog, isToday };
    });

    // Generate Blanks for grid alignment
    const blanks = Array.from({ length: firstDayIndex }, (_, i) => i);

    return (
        <div className="px-4">
             {/* Navigation */}
             <div className="flex items-center justify-between mb-6 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p - 1)} 
                    disabled={isPrevDisabled}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark uppercase tracking-wide">
                      {targetDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p + 1)} 
                    disabled={isNextDisabled} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

             <div className="grid grid-cols-7 gap-3">
                {['S','M','T','W','T','F','S'].map((d,i) => (
                    <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase mb-2">{d}</div>
                ))}

                {/* Blanks */}
                {blanks.map(i => (
                    <div key={`blank-${i}`} />
                ))}

                {/* Days */}
                {days.map(d => (
                    <div 
                        key={d.dateStr}
                        className={`aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all
                            ${d.hasLog 
                                ? 'bg-ledger-accent text-white shadow-sm' 
                                : 'bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800'}
                            ${d.isToday ? 'ring-2 ring-ledger-accent ring-offset-1 dark:ring-offset-ledger-bgDark' : ''}
                        `}
                    >
                        {d.dayNum}
                    </div>
                ))}
             </div>
        </div>
    );
  };

  // --- VIEW: WEEK (Chart) ---
  const renderWeekView = () => {
      // Calculate selected week range
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay();
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff); // This is Sunday of selected week

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];
          const log = state.logs.find(l => l.date === dateStr);

          const active = state.habits.filter(h => h.isActive).length || 1;
          const completed = log?.completedHabitIds.length || 0;
          const pct = Math.min((completed / active) * 100, 100);
          const isDifferentYear = d.getFullYear() !== currentYear;

          return { 
              label: d.toLocaleDateString('en-US', { weekday: 'narrow' }), 
              pct, 
              dateStr,
              isDifferentYear
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      // Prevent navigating before the first week of the year
      const isEarliestWeek = selectedWeekOffset <= -currentWeekIndex;

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${Math.max(d.pct, 4)}%` }} // Min height for visibility
                              />
                          </div>
                          <span className="text-xs font-bold text-ledger-muted uppercase">{d.label}</span>
                      </div>
                  ))}
              </div>
              <p className="text-center text-[10px] text-ledger-muted mt-4">
                Gray columns indicate days outside the current year.
              </p>
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-8 mx-2">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                    if(mode === 'Month') setSelectedMonthOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in">
          {view === 'Year' && (
              <div>
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
                  <p className="text-center text-[10px] text-ledger-muted mt-6">Each box represents a week. Fill level indicates active days.</p>
              </div>
          )}
          {view === 'Month' && renderMonthView()}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { User, Check, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Today: React.FC = () => {
  const { state, toggleHabit } = useApp();
  const navigate = useNavigate();
  const [expandedHabitId, setExpandedHabitId] = useState<string | null>(null);

  // --- DATE MATH ---
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const dayOfWeek = today.getDay(); // 0 = Sun, 6 = Sat

  // Calculate Start of Week (Sunday)
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  // Calculate End of Week (Saturday)
  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  // Generate Array of 7 days for the header
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    return {
        dateStr: d.toISOString().split('T')[0],
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: d.toISOString().split('T')[0] === todayStr,
        isFuture: d.toISOString().split('T')[0] > todayStr
    };
  });

  const activeHabits = state.habits.filter(h => h.isActive);

  // Weekly Score Calculation
  const weekLogs = state.logs.filter(l => l.date >= weekDays[0].dateStr && l.date <= weekDays[6].dateStr);
  const totalCompleted = weekLogs.reduce((acc, log) => acc + log.completedHabitIds.length, 0);
  const totalPotential = Math.max(activeHabits.length * 7, 1);
  const weeklyPercentage = (totalCompleted / totalPotential) * 100;

  const handleToggle = (id: string, date: string, isFuture: boolean) => {
    if (isFuture) return;
    toggleHabit(id, date);
  };

  const toggleExpand = (id: string) => {
      setExpandedHabitId(prev => prev === id ? null : id);
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative font-sans">
      {/* Header */}
      <header className="px-6 py-5 flex items-center justify-between sticky top-0 z-30 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl border-b border-ledger-border dark:border-ledger-borderDark">
        <div>
            <h1 className="text-base font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">
                Current Week
            </h1>
            <p className="text-xs text-ledger-muted mt-0.5 font-medium">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </p>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark hover:opacity-70 transition-opacity">
          <User size={22} strokeWidth={2} />
        </button>
      </header>

      {/* KPI Section */}
      <div className="px-6 py-6 border-b border-ledger-border dark:border-ledger-borderDark bg-white dark:bg-[#111111]">
         <div className="flex items-center justify-between">
             <div>
                <div className="text-4xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tight">
                    {Math.round(weeklyPercentage)}%
                </div>
                <div className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mt-1">Completion</div>
             </div>

             <div className="flex flex-col items-end gap-1">
                 <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 dark:bg-white/10 rounded-md">
                    <Zap size={14} className="text-ledger-accent" fill="currentColor" />
                    <span className="text-xs font-bold text-ledger-text dark:text-ledger-textDark">{state.repairTokens}</span>
                 </div>
                 <span className="text-[10px] font-medium text-ledger-muted">Repairs Left</span>
             </div>
         </div>
      </div>

      {/* Main Grid - Two Column Layout with Scroll */}
      <div className="flex-1 overflow-auto no-scrollbar pb-24 relative">
         <div className="inline-block min-w-full align-middle">
             {/* Sticky Header Row */}
             <div className="sticky top-0 z-20 flex border-b border-ledger-border dark:border-ledger-borderDark bg-ledger-bg dark:bg-ledger-bgDark shadow-sm">
                 {/* Left Column Header (Fixed) */}
                 <div className="sticky left-0 z-30 w-[28vw] flex-none px-4 py-4 bg-ledger-bg dark:bg-ledger-bgDark border-r border-gray-100 dark:border-gray-800">
                     <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider">Task</span>
                 </div>

                 {/* Right Column Header (Scrollable content) */}
                 <div className="flex-1 flex min-w-max px-2">
                     {weekDays.map(d => (
                         <div key={d.dateStr} className={`w-14 flex flex-col items-center justify-center gap-1.5 py-4 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                             <span className="text-[10px] font-bold uppercase tracking-wider">{d.label}</span>
                             <span className={`text-xs font-bold w-6 h-6 flex items-center justify-center rounded-full transition-colors ${d.isToday ? 'bg-ledger-accent text-white shadow-md' : 'bg-transparent text-inherit'}`}>
                                 {d.dayNum}
                             </span>
                         </div>
                     ))}
                 </div>
             </div>

             {/* Rows */}
             <div className="divide-y divide-gray-100 dark:divide-gray-800/50">
                 {activeHabits.map(habit => {
                     const isExpanded = expandedHabitId === habit.id;
                     return (
                         <div key={habit.id} className="flex group bg-white dark:bg-ledger-bgDark">
                             {/* Left Column (Task Name - Fixed) */}
                             <button 
                                onClick={() => toggleExpand(habit.id)}
                                className={`sticky left-0 z-10 w-[28vw] flex-none px-4 py-3 text-left border-r border-gray-100 dark:border-gray-800 bg-white dark:bg-ledger-bgDark transition-colors flex items-center ${isExpanded ? 'items-start' : 'items-center'}`}
                             >
                                 <span className={`text-sm font-semibold text-ledger-text dark:text-ledger-textDark transition-all duration-200 block ${isExpanded ? 'whitespace-normal' : 'truncate'}`}>
                                     {habit.name}
                                 </span>
                             </button>

                             {/* Right Column (Days - Scrollable) */}
                             <div className="flex-1 flex min-w-max px-2 items-center">
                                 {weekDays.map(d => {
                                     const log = state.logs.find(l => l.date === d.dateStr);
                                     const isCompleted = log?.completedHabitIds.includes(habit.id);
                                     const isRepaired = log?.repairedHabitIds?.includes(habit.id);

                                     // High Contrast Styles
                                     let cellContent = null;
                                     let cellClass = "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-200 border-2";

                                     if (d.isFuture) {
                                         cellClass += " border-transparent bg-gray-50 dark:bg-white/5 opacity-30 cursor-not-allowed";
                                     } else if (isCompleted) {
                                         if (isRepaired) {
                                            // Repaired
                                            cellClass += " border-ledger-accent text-ledger-accent bg-transparent";
                                            cellContent = <div className="w-3 h-3 rounded-full bg-ledger-accent" />;
                                         } else {
                                             // Normal
                                             cellClass += " border-ledger-accent bg-ledger-accent text-white shadow-sm";
                                             cellContent = <Check size={20} strokeWidth={4} />;
                                         }
                                     } else {
                                         // Empty
                                         cellClass += " border-gray-200 dark:border-gray-800 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent/50";
                                     }

                                     return (
                                         <div key={d.dateStr} className="w-14 flex justify-center py-2">
                                             <button
                                                onClick={() => handleToggle(habit.id, d.dateStr, d.isFuture)}
                                                disabled={d.isFuture}
                                                className="active:scale-95 transition-transform"
                                             >
                                                 <div className={cellClass}>
                                                     {cellContent}
                                                 </div>
                                             </button>
                                         </div>
                                     );
                                 })}
                             </div>
                         </div>
                     );
                 })}
             </div>

             {activeHabits.length === 0 && (
                <div className="p-8 text-center text-ledger-muted sticky left-0">
                    No active habits. Go to Habits tab to add some.
                </div>
             )}
         </div>
      </div>
    </div>
  );
};

export interface Habit {
  id: string;
  name: string;
  isActive: boolean;
  sortOrder: number;
}

export interface DailyLog {
  date: string; // YYYY-MM-DD
  completedHabitIds: string[];
  repairedHabitIds?: string[]; // IDs of habits logged via "Repair" token
}

export interface Achievement {
  id: string;
  title: string;
  description: string;
  targetValue: number;
  type: 'streak' | 'total_logs' | 'perfect_days';
  unlockedAt?: string; // ISO Date string
}

export interface AppState {
  habits: Habit[];
  logs: DailyLog[];
  achievements: Achievement[];
  isOnboarded: boolean;
  theme: 'light' | 'dark';
  repairTokens: number;
  lastTokenReset: string; // ISO Date string (YYYY-MM-DD)
  dataYear: number;
}

export const MAX_HABITS = 50;

export const DEFAULT_SUGGESTIONS = [
  "Exercise",
  "Reading",
  "Deep work",
  "Language practice",
  "Meditation",
  "No alcohol"
];

