                placeholder="test123"
                onKeyDown={(e) => e.key === 'Enter' && handleLogin()}
              />
              <button 
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-0 top-2 text-ledger-muted hover:text-ledger-text dark:hover:text-ledger-textDark"
              >
                {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
