  logs: DailyLog[];
  achievements: Achievement[];
  isOnboarded: boolean;
  theme: ThemeOption;
  repairTokens: number;
  lastTokenReset: string; // ISO Date string (YYYY-MM-DD)
  dataYear: number;
  weeklySnapshot: HabitSnapshot[]; // Habits active for the current week (changes apply next week)
}

