import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, MAX_HABITS, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => void;
  toggleHabit: (habitId: string, date: string) => void;
  updateHabitName: (id: string, name: string) => void;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  completeOnboarding: () => void;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  lastTokenReset: new Date().toISOString().split('T')[0],
  dataYear: new Date().getFullYear(),
  weeklySnapshot: []
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<AppState>(() => {
    const saved = localStorage.getItem('ledger_app_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      // Migrations
      if (!parsed.achievements || parsed.achievements.length === 0) {
        parsed.achievements = STATIC_ACHIEVEMENTS.map(a => ({ ...a }));
      }
      if (parsed.repairTokens === undefined) {
        parsed.repairTokens = 3;
        parsed.lastTokenReset = new Date().toISOString().split('T')[0];
      }
      if (!parsed.dataYear) {
        parsed.dataYear = new Date().getFullYear();
      }
      // Migration: Initialize weeklySnapshot if missing
      if (!parsed.weeklySnapshot && parsed.habits) {
        parsed.weeklySnapshot = parsed.habits
            .filter((h: Habit) => h.isActive)
            .map((h: Habit) => ({ id: h.id, name: h.name }));
      }
      return parsed;
    }
    return defaultState;
  });

  // --- ANNUAL RESET CHECK ---
  useEffect(() => {
      const currentYear = new Date().getFullYear();
      if (state.dataYear !== currentYear) {
          // Trigger Annual Reset
          setState(prev => ({
              ...prev,
              dataYear: currentYear,
              logs: [], // Clear all logs
              repairTokens: 3,
              // Reset Achievements to locked state
              achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a }))
          }));
      }
  }, [state.dataYear]);

  // --- WEEKLY LOGIC (Repair Tokens & Habit Snapshot) ---
  useEffect(() => {
    const today = new Date();
    const todayStr = today.toISOString().split('T')[0];

    // Check if we need to reset tokens (Sunday is start of week)
    const lastResetDate = new Date(state.lastTokenReset);

    const getWeekStart = (d: Date) => {
        const date = new Date(d);
        const day = date.getDay(); 
        const diff = date.getDate() - day; // Sunday
        return new Date(date.setDate(diff)).toISOString().split('T')[0];
    };

    const currentWeekStart = getWeekStart(today);
    const lastResetWeekStart = getWeekStart(lastResetDate);

    if (currentWeekStart > lastResetWeekStart) {
        // New week started
        setState(prev => ({
            ...prev,
            repairTokens: 3,
            lastTokenReset: todayStr,
            // Freeze habits for the new week based on current config
            weeklySnapshot: prev.habits
                .filter(h => h.isActive)
                .map(h => ({ id: h.id, name: h.name }))
        }));
    }
  }, [state.lastTokenReset]);

  // --- STATS CALCULATION ---
  const calculateStats = () => {
    const todayStr = new Date().toISOString().split('T')[0];
    // For general stats, we check currently active habits in config
    const activeHabitCount = state.habits.filter(h => h.isActive).length;

    // 1. Total Logged Days
    const totalLoggedDays = state.logs.length;

    // 2. Perfect Days
    const perfectDays = state.logs.filter(log => {
      if (activeHabitCount === 0) return false;
      return log.completedHabitIds.length >= activeHabitCount;
    }).length;

    // 3. Current Streak
    let currentStreak = 0;
    const sortedLogs = [...state.logs].sort((a, b) => b.date.localeCompare(a.date));

    if (sortedLogs.length > 0) {
      const lastLogDate = new Date(sortedLogs[0].date);
      const todayDate = new Date(todayStr);
      const diffTime = Math.abs(todayDate.getTime() - lastLogDate.getTime());
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

      if (diffDays <= 1) {
        currentStreak = 1;
        let prevDate = lastLogDate;

        for (let i = 1; i < sortedLogs.length; i++) {
          const currentDate = new Date(sortedLogs[i].date);
          const gap = Math.abs(prevDate.getTime() - currentDate.getTime());
          const gapDays = Math.round(gap / (1000 * 60 * 60 * 24));

          if (gapDays === 1) {
            currentStreak++;
            prevDate = currentDate;
          } else {
            break;
          }
        }
      }
    }

    // 4. Weekly Score
    const oneWeekAgo = new Date();
    oneWeekAgo.setDate(oneWeekAgo.getDate() - 6);
    const oneWeekAgoStr = oneWeekAgo.toISOString().split('T')[0];

    const logsLast7Days = state.logs.filter(l => l.date >= oneWeekAgoStr && l.date <= todayStr);
    const totalCompletedLast7 = logsLast7Days.reduce((acc, log) => acc + log.completedHabitIds.length, 0);
    // Use snapshot length for consistency in current view, or generic active count
    // Sticking to activeHabitCount for general stats to reflect total potential
    const potentialTotal = (activeHabitCount || 1) * 7; 
    const weeklyScore = totalCompletedLast7 / potentialTotal;

    return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const stats = {
    ...calculateStats(),
    getHabitConsistency: (habitId: string) => {
        const oneWeekAgo = new Date();
        oneWeekAgo.setDate(oneWeekAgo.getDate() - 6);
        const oneWeekAgoStr = oneWeekAgo.toISOString().split('T')[0];
        const todayStr = new Date().toISOString().split('T')[0];

        const relevantLogs = state.logs.filter(l => l.date >= oneWeekAgoStr && l.date <= todayStr);
        const count = relevantLogs.filter(l => l.completedHabitIds.includes(habitId)).length;
        return (count / 7) * 100;
    }
  };

  // --- ACHIEVEMENT WATCHER ---
  useEffect(() => {
    let hasChanges = false;
    const newAchievements = state.achievements.map(ach => {
      if (ach.unlockedAt) return ach; // Already unlocked

      let isUnlocked = false;
      if (ach.type === 'streak' && stats.currentStreak >= ach.targetValue) isUnlocked = true;
      if (ach.type === 'total_logs' && stats.totalLoggedDays >= ach.targetValue) isUnlocked = true;
      if (ach.type === 'perfect_days' && stats.perfectDays >= ach.targetValue) isUnlocked = true;

      if (isUnlocked) {
        hasChanges = true;
        return { ...ach, unlockedAt: new Date().toISOString() };
      }
      return ach;
    });

    if (hasChanges) {
      setState(prev => ({ ...prev, achievements: newAchievements }));
    }
  }, [state.logs, state.habits]);

  // Persistence & Theme Application
  useEffect(() => {
    localStorage.setItem('ledger_app_data', JSON.stringify(state));

    // Remove all previous theme classes
    const html = document.documentElement;
    html.classList.remove(
      'dark', 
      'theme-dark', 
      'theme-vintage', 
      'theme-sepia', 
      'theme-cyberpunk',
      'theme-nordic',
      'theme-high-contrast',
      'theme-zen',
      'theme-oled',
      'theme-blue-light'
    );

    // Apply new theme class
    if (state.theme !== 'light') {
        html.classList.add(`theme-${state.theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [state.theme, state]);

  const addHabit = (name: string) => {
    if (state.habits.filter(h => h.isActive).length >= MAX_HABITS) return;

    const safeName = name.slice(0, 17); // Enforce limit

    const newHabit: Habit = {
      id: crypto.randomUUID(),
      name: safeName,
      isActive: true,
      sortOrder: state.habits.length
    };

    setState(prev => ({
      ...prev,
      habits: [...prev.habits, newHabit]
    }));
  };

  const toggleHabit = (habitId: string, date: string) => {
    const todayStr = new Date().toISOString().split('T')[0];
    const isPast = date < todayStr;
    const isToday = date === todayStr;

    if (date > todayStr) return;

    // Check same week for repairs
    const targetDate = new Date(date);
    const todayDate = new Date(todayStr);

    const currentWeekStart = new Date(todayDate);
    currentWeekStart.setDate(todayDate.getDate() - todayDate.getDay());
    const targetWeekStart = new Date(targetDate);
    targetWeekStart.setDate(targetDate.getDate() - targetDate.getDay());

    const isDifferentWeek = currentWeekStart.getTime() !== targetWeekStart.getTime();

    if (isPast && isDifferentWeek) {
        alert("Past weeks are locked.");
        return;
    }

    setState(prev => {
      const existingLogIndex = prev.logs.findIndex(l => l.date === date);
      let newLogs = [...prev.logs];
      let newTokens = prev.repairTokens;

      if (existingLogIndex >= 0) {
        const log = newLogs[existingLogIndex];
        const isCompleted = log.completedHabitIds.includes(habitId);

        let newCompletedIds;
        let newRepairedIds = log.repairedHabitIds || [];

        if (isCompleted) {
          // Unchecking (Undo)
          newCompletedIds = log.completedHabitIds.filter(id => id !== habitId);

          if (newRepairedIds.includes(habitId)) {
             // Undo a repair: REFUND TOKEN
             newRepairedIds = newRepairedIds.filter(id => id !== habitId);
             newTokens = Math.min(newTokens + 1, 3); // Cap at 3 or just increment
          }
        } else {
          // Checking (Complete)
          if (isPast) {
             if (newTokens > 0) {
                 newTokens -= 1;
                 newCompletedIds = [...log.completedHabitIds, habitId];
                 newRepairedIds = [...newRepairedIds, habitId];
             } else {
                 alert("No repair tokens remaining for this week.");
                 return prev;
             }
          } else {
             newCompletedIds = [...log.completedHabitIds, habitId];
          }
        }

        newLogs[existingLogIndex] = { 
            ...log, 
            completedHabitIds: newCompletedIds,
            repairedHabitIds: newRepairedIds
        };
      } else {
        // Create new log
        if (isPast) {
            if (newTokens > 0) {
                newTokens -= 1;
                newLogs.push({
                    date,
                    completedHabitIds: [habitId],
                    repairedHabitIds: [habitId]
                });
            } else {
                alert("No repair tokens remaining for this week.");
                return prev;
            }
        } else {
            newLogs.push({
                date,
                completedHabitIds: [habitId],
                repairedHabitIds: []
            });
        }
      }

      return { ...prev, logs: newLogs, repairTokens: newTokens };
    });
  };

  const updateHabitName = (id: string, name: string) => {
    const safeName = name.slice(0, 17); // Enforce limit
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, name: safeName } : h)
    }));
  };

  const archiveHabit = (id: string) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, isActive: false } : h)
    }));
  };

  const restoreHabit = (id: string) => {
    if (state.habits.filter(h => h.isActive).length >= MAX_HABITS) return;
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => h.id === id ? { ...h, isActive: true } : h)
    }));
  };

  const reorderHabits = (fromIndex: number, toIndex: number) => {
    setState(prev => {
      const activeHabits = prev.habits.filter(h => h.isActive);
      const archivedHabits = prev.habits.filter(h => !h.isActive);

      const newActive = [...activeHabits];
      const [moved] = newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);

      return { ...prev, habits: [...newActive, ...archivedHabits] };
    });
  };

  const completeOnboarding = () => {
    setState(prev => ({ 
        ...prev, 
        isOnboarded: true,
        // Establish initial snapshot on onboarding complete
        weeklySnapshot: prev.habits
            .filter(h => h.isActive)
            .map(h => ({ id: h.id, name: h.name }))
    }));
  };

  const setTheme = (theme: ThemeOption) => {
    setState(prev => ({ ...prev, theme }));
  };

  const resetData = () => {
    if(confirm("Delete all data? This cannot be undone.")) {
        setState(defaultState);
        window.location.reload();
    }
  };

  const exportData = () => {
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(state));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "ledger_export.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <AppContext.Provider value={{ 
      state, addHabit, toggleHabit, updateHabitName, archiveHabit, 
      restoreHabit, reorderHabits, completeOnboarding, setTheme, resetData, exportData,
      stats
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { User, Check, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Today: React.FC = () => {
  const { state, toggleHabit } = useApp();
  const navigate = useNavigate();
  const [expandedHabitId, setExpandedHabitId] = useState<string | null>(null);

  // --- DATE MATH ---
  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const dayOfWeek = today.getDay(); // 0 = Sun, 6 = Sat

  // Calculate Start of Week (Sunday)
  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  // Calculate End of Week (Saturday)
  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  // Generate Array of 7 days for the header
  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    return {
        dateStr: d.toISOString().split('T')[0],
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: d.toISOString().split('T')[0] === todayStr,
        isFuture: d.toISOString().split('T')[0] > todayStr
    };
  });

  // Use weeklySnapshot for consistency within the week (changes apply next week)
  // Fallback to active habits if snapshot is empty (should only happen during dev/migration)
  const displayHabits = state.weeklySnapshot.length > 0 
      ? state.weeklySnapshot 
      : state.habits.filter(h => h.isActive);

  // Weekly Score Calculation
  const weekLogs = state.logs.filter(l => l.date >= weekDays[0].dateStr && l.date <= weekDays[6].dateStr);
  const totalCompleted = weekLogs.reduce((acc, log) => acc + log.completedHabitIds.length, 0);
  const totalPotential = Math.max(displayHabits.length * 7, 1);
  const weeklyPercentage = (totalCompleted / totalPotential) * 100;

  const handleToggle = (id: string, date: string, isFuture: boolean) => {
    if (isFuture) return;
    toggleHabit(id, date);
  };

  const toggleExpand = (id: string) => {
      setExpandedHabitId(prev => prev === id ? null : id);
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative font-sans">
      {/* Header */}
      <header className="px-6 py-5 flex items-center justify-between sticky top-0 z-50 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl border-b border-ledger-border dark:border-ledger-borderDark">
        <div>
            <h1 className="text-base font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">
                Current Week
            </h1>
            <p className="text-xs text-ledger-muted mt-0.5 font-medium">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </p>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark hover:opacity-70 transition-opacity">
          <User size={22} strokeWidth={2} />
        </button>
      </header>

      {/* KPI Section */}
      <div className="px-6 py-6 border-b border-ledger-border dark:border-ledger-borderDark bg-white dark:bg-[#111111]">
         <div className="flex items-center justify-between">
             <div>
                <div className="text-4xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tight">
                    {Math.round(weeklyPercentage)}%
                </div>
                <div className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mt-1">Completion</div>
             </div>

             <div className="flex flex-col items-end gap-1">
                 <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 dark:bg-white/10 rounded-md">
                    <Zap size={14} className="text-ledger-accent" fill="currentColor" />
                    <span className="text-xs font-bold text-ledger-text dark:text-ledger-textDark">{state.repairTokens}</span>
                 </div>
                 <span className="text-[10px] font-medium text-ledger-muted">Repairs Left</span>
             </div>
         </div>
      </div>

      {/* Main Grid - Table Layout for Dynamic Sizing */}
      <div className="flex-1 overflow-auto no-scrollbar pb-24 relative bg-ledger-bg dark:bg-ledger-bgDark">
         <table className="border-collapse min-w-full">
            <thead className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark shadow-sm">
                <tr>
                    {/* Top Left Corner - Sticky Both Directions */}
                    <th className="sticky left-0 top-0 z-50 bg-ledger-bg dark:bg-ledger-bgDark border-b border-r border-gray-100 dark:border-gray-800 px-4 py-4 text-left">
                        <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider whitespace-nowrap">Task</span>
                    </th>
                    {/* Day Headers */}
                    {weekDays.map(d => (
                        <th key={d.dateStr} className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark border-b border-gray-100 dark:border-gray-800 px-2 py-4 min-w-[60px]">
                            <div className={`flex flex-col items-center justify-center gap-1.5 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                                <span className="text-[10px] font-bold uppercase tracking-wider">{d.label}</span>
                                <span className={`text-xs font-bold w-6 h-6 flex items-center justify-center rounded-full transition-colors ${d.isToday ? 'bg-ledger-accent text-white shadow-md' : 'bg-transparent text-inherit'}`}>
                                    {d.dayNum}
                                </span>
                            </div>
                        </th>
                    ))}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800/50">
                {displayHabits.map(habit => (
                    <tr key={habit.id} className="group bg-white dark:bg-ledger-bgDark">
                        {/* Task Name - Sticky Left */}
                        <td className="sticky left-0 z-30 bg-white dark:bg-ledger-bgDark border-r border-gray-100 dark:border-gray-800 px-4 py-3 whitespace-nowrap">
                            <span className="text-sm font-semibold text-ledger-text dark:text-ledger-textDark">
                                {habit.name}
                            </span>
                        </td>

                        {/* Day Cells */}
                        {weekDays.map(d => {
                             const log = state.logs.find(l => l.date === d.dateStr);
                             const isCompleted = log?.completedHabitIds.includes(habit.id);
                             const isRepaired = log?.repairedHabitIds?.includes(habit.id);

                             // Styles
                             let cellContent = null;
                             let cellClass = "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-200 border-2 mx-auto";

                             if (d.isFuture) {
                                 cellClass += " border-transparent bg-gray-50 dark:bg-white/5 opacity-30 cursor-not-allowed";
                             } else if (isCompleted) {
                                 if (isRepaired) {
                                    // Repaired
                                    cellClass += " border-ledger-accent text-ledger-accent bg-transparent";
                                    cellContent = <div className="w-3 h-3 rounded-full bg-ledger-accent" />;
                                 } else {
                                     // Normal
                                     cellClass += " border-ledger-accent bg-ledger-accent text-white shadow-sm";
                                     cellContent = <Check size={20} strokeWidth={4} />;
                                 }
                             } else {
                                 // Empty
                                 cellClass += " border-gray-200 dark:border-gray-800 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent/50";
                             }

                            return (
                                <td key={d.dateStr} className="px-2 py-2">
                                     <button
                                        onClick={() => handleToggle(habit.id, d.dateStr, d.isFuture)}
                                        disabled={d.isFuture}
                                        className="active:scale-95 transition-transform block w-full"
                                     >
                                         <div className={cellClass}>
                                             {cellContent}
                                         </div>
                                     </button>
                                </td>
                            );
                        })}
                    </tr>
                ))}
            </tbody>
         </table>

         {displayHabits.length === 0 && (
            <div className="p-8 text-center text-ledger-muted">
                No active habits. Go to Habits tab to add some.
            </div>
         )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight } from 'lucide-react';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); // 0 = Current week
  const [selectedMonthOffset, setSelectedMonthOffset] = useState(0); // 0 = Current month

  const today = new Date();
  const currentYear = today.getFullYear();

  // Helper
  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; // 0-indexed for array mapping
  };

  const currentWeekIndex = getWeekNumber(today);

  // --- VIEW: YEAR (Water Fill) ---
  const renderYearView = () => {
    // Generate 53 weeks
    const weeks = [];
    let d = new Date(currentYear, 0, 1);

    // Adjust to first Sunday of the year or before
    while (d.getDay() !== 0) {
        d.setDate(d.getDate() - 1);
    }

    for (let i = 0; i < 53; i++) {
        const weekStart = new Date(d);
        const weekEnd = new Date(d);
        weekEnd.setDate(weekEnd.getDate() + 6);

        // Count days logged in this week
        const startStr = weekStart.toISOString().split('T')[0];
        const endStr = weekEnd.toISOString().split('T')[0];

        const logsInWeek = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
        // We count unique days logged, not total habits
        const daysLogged = new Set(logsInWeek.map(l => l.date)).size;
        const fillPercent = (daysLogged / 7) * 100;

        weeks.push({ 
            id: i, 
            fillPercent, 
            startDate: weekStart,
            isCurrent: i === currentWeekIndex,
            weekNum: i + 1
        });

        // Advance 1 week
        d.setDate(d.getDate() + 7);
    }

    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {weeks.map((w) => (
                <button
                    key={w.id}
                    onClick={() => {
                        // Calculate offset from current week
                        const offset = w.id - currentWeekIndex;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border border-gray-200 dark:border-gray-800 relative overflow-hidden flex items-end justify-center ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}`}
                >
                    <div 
                        className="absolute inset-x-0 bottom-0 bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                        style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                    />
                    <span className="relative z-10 text-[10px] font-bold text-ledger-text dark:text-ledger-textDark mix-blend-difference mb-1">
                        {w.weekNum}
                    </span>
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH (Calendar) ---
  const renderMonthView = () => {
    // Calculate Target Month
    const targetDate = new Date(today.getFullYear(), today.getMonth() + selectedMonthOffset, 1);
    const targetMonth = targetDate.getMonth();
    const targetYear = targetDate.getFullYear();

    // Limits: Cannot go before Jan 1st of current year, or after Dec 31st of current year
    const minOffset = -today.getMonth(); // Back to Jan
    const maxOffset = 11 - today.getMonth(); // Forward to Dec

    const isPrevDisabled = selectedMonthOffset <= minOffset;
    const isNextDisabled = selectedMonthOffset >= maxOffset;

    // Calendar Math
    const daysInMonth = new Date(targetYear, targetMonth + 1, 0).getDate();
    const firstDayIndex = new Date(targetYear, targetMonth, 1).getDay(); // 0 = Sunday

    // Generate Days
    const days = Array.from({ length: daysInMonth }, (_, i) => {
        const d = new Date(targetYear, targetMonth, i + 1);
        const dateStr = d.toISOString().split('T')[0];
        const hasLog = state.logs.some(l => l.date === dateStr && l.completedHabitIds.length > 0);
        const isToday = dateStr === today.toISOString().split('T')[0];
        return { dateStr, dayNum: i + 1, hasLog, isToday };
    });

    // Generate Blanks for grid alignment
    const blanks = Array.from({ length: firstDayIndex }, (_, i) => i);

    return (
        <div className="px-4">
             {/* Navigation */}
             <div className="flex items-center justify-between mb-6 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p - 1)} 
                    disabled={isPrevDisabled}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark uppercase tracking-wide">
                      {targetDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p + 1)} 
                    disabled={isNextDisabled} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

             <div className="grid grid-cols-7 gap-3">
                {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase mb-2">{d}</div>
                ))}

                {/* Blanks */}
                {blanks.map(i => (
                    <div key={`blank-${i}`} />
                ))}

                {/* Days */}
                {days.map(d => (
                    <div 
                        key={d.dateStr}
                        className={`aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all
                            ${d.hasLog 
                                ? 'bg-ledger-accent text-white shadow-sm' 
                                : 'bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800'}
                            ${d.isToday ? 'ring-2 ring-ledger-accent ring-offset-1 dark:ring-offset-ledger-bgDark' : ''}
                        `}
                    >
                        {d.dayNum}
                    </div>
                ))}
             </div>
        </div>
    );
  };

  // --- VIEW: WEEK (Chart) ---
  const renderWeekView = () => {
      // Calculate selected week range
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay();
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff); // This is Sunday of selected week

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];
          const log = state.logs.find(l => l.date === dateStr);

          const active = state.habits.filter(h => h.isActive).length || 1;
          const completed = log?.completedHabitIds.length || 0;
          const pct = Math.min((completed / active) * 100, 100);
          const isDifferentYear = d.getFullYear() !== currentYear;

          return { 
              label: d.toLocaleDateString('en-US', { weekday: 'narrow' }), 
              pct, 
              dateStr,
              isDifferentYear
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      // Prevent navigating before the first week of the year
      const isEarliestWeek = selectedWeekOffset <= -currentWeekIndex;

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${Math.max(d.pct, 4)}%` }} // Min height for visibility
                              />
                          </div>
                          <span className="text-xs font-bold text-ledger-muted uppercase">{d.label}</span>
                      </div>
                  ))}
              </div>
              <p className="text-center text-[10px] text-ledger-muted mt-4">
                Gray columns indicate days outside the current year.
              </p>
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-8 mx-2">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                    if(mode === 'Month') setSelectedMonthOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in">
          {view === 'Year' && (
              <div>
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
                  <p className="text-center text-[10px] text-ledger-muted mt-6">Each box represents a week. Fill level indicates active days.</p>
              </div>
          )}
          {view === 'Month' && renderMonthView()}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

