import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword } from 'firebase/auth';

type Step = 'selection' | 'auth';

export const Onboarding: React.FC = () => {
  const { addHabit, completeOnboarding } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('selection');
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const handleContinue = () => {
    setStep('auth');
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        if (isSignUp) {
            await createUserWithEmailAndPassword(auth, email, password);
        } else {
            await signInWithEmailAndPassword(auth, email, password);
        }

        // On success:
        // Add selected habits (only if signing up or first time, but logic is safe to repeat or we can check)
        selected.forEach(habitName => addHabit(habitName));

        completeOnboarding();
        navigate('/today');

    } catch (error: any) {
        console.error("Auth error:", error);
        let msg = "An unexpected error occurred.";
        if (error.code === 'auth/invalid-credential' || error.code === 'auth/user-not-found' || error.code === 'auth/wrong-password') {
            msg = "Invalid email or password.";
        } else if (error.code === 'auth/email-already-in-use') {
            msg = "Email is already in use.";
        } else if (error.code === 'auth/weak-password') {
            msg = "Password should be at least 6 characters.";
        } else if (error.code === 'auth/invalid-email') {
            msg = "Invalid email address.";
        }
        setAuthError(msg);
    } finally {
        setIsLoading(false);
    }
  };

  // Selection Step View
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative overflow-hidden">
