                <div className="mb-6 space-y-2">
                    {selected.map((item) => (
                        <div key={item} className="flex items-center justify-between p-3 bg-white dark:bg-ledger-surfaceDark rounded-md border border-ledger-border dark:border-ledger-borderDark animate-fade-in">
                            <span className="font-medium text-ledger-text dark:text-ledger-textDark">{item}</span>
                            <button onClick={() => toggleSelection(item)} className="text-ledger-muted hover:text-red-500">
                                <X size={16} />
                            </button>
                        </div>
                    ))}
                </div>
            )}

            <div className="space-y-4 mb-8">
                <div className="flex flex-wrap gap-2">
                    {DEFAULT_SUGGESTIONS.map(suggestion => {
                        const isSelected = selected.includes(suggestion);
                        return (
                            <button
                                key={suggestion}
                                onClick={() => toggleSelection(suggestion)}
                                className={`px-4 py-2 rounded-full text-sm font-medium transition-all duration-200 border
                                    ${isSelected 
                                        ? 'bg-ledger-accent text-white border-ledger-accent' 
                                        : 'bg-transparent text-ledger-text dark:text-ledger-textDark border-ledger-border dark:border-ledger-borderDark hover:border-ledger-accent'
                                    }
                                `}
                            >
                                {suggestion}
                            </button>
                        );
                    })}
                </div>
            </div>

            <div className="flex gap-2 mb-4">
                <input 
                    type="text" 
                    value={customHabit}
                    onChange={(e) => setCustomHabit(e.target.value)}
                    placeholder="Add custom habit..."
                    className="flex-1 bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent placeholder-ledger-muted"
                    onKeyDown={(e) => e.key === 'Enter' && addCustom()}
                    maxLength={17}
                />
                <button 
                    onClick={addCustom}
                    disabled={!customHabit}
                    className="text-ledger-accent font-medium disabled:opacity-30"
                >
                    Add
                </button>
            </div>
          </div>
        </div>

        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-ledger-bg via-ledger-bg to-transparent dark:from-ledger-bgDark dark:via-ledger-bgDark pt-12">
          <p className="text-center text-sm text-ledger-muted mb-4">
            {selected.length} selected
          </p>
          <Button 
            fullWidth 
            onClick={handleContinue} 
            disabled={selected.length === 0}
          >
            Continue
          </Button>
        </div>
      </div>
    );
  }

  // Auth Step View
  return (
    <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto">
      <div className="mb-8 mt-2">
        <button 
          onClick={() => setStep('selection')}
          className="flex items-center text-ledger-muted hover:text-ledger-text dark:hover:text-ledger-textDark transition-colors"
        >
          <ChevronLeft size={20} className="mr-1" />
          Back
        </button>
      </div>

      <div className="flex-1 flex flex-col justify-center max-w-sm mx-auto w-full">
        <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">
          {isSignUp ? 'Create an account' : 'Welcome back'}
        </h2>
        <p className="text-ledger-muted mb-8">
          Save your preferences and start tracking.
        </p>

        <div className="space-y-6">
          <div>
            <label className="block text-xs font-semibold uppercase text-ledger-muted mb-2">Email</label>
            <input 
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent transition-colors"
              placeholder="you@example.com"
            />
          </div>

          <div>
            <label className="block text-xs font-semibold uppercase text-ledger-muted mb-2">Password</label>
            <div className="relative">
              <input 
                type={showPassword ? "text" : "password"}
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent transition-colors pr-10"
                placeholder="••••••"
                onKeyDown={(e) => e.key === 'Enter' && handleAuth()}
              />
              <button 
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-0 top-2 text-ledger-muted hover:text-ledger-text dark:hover:text-ledger-textDark"
              >
                {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
              </button>
            </div>
          </div>
        </div>

        {authError && (
          <div className="mt-4 p-3 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 text-sm animate-fade-in">
            {authError}
          </div>
        )}

        <div className="mt-10">
          <Button fullWidth onClick={handleAuth} disabled={isLoading}>
            {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
          </Button>

          <div className="mt-6 flex justify-center">
              <button 
                onClick={() => {
                    setIsSignUp(!isSignUp);
                    setAuthError('');
                }}
                className="text-xs text-ledger-muted hover:text-ledger-text dark:hover:text-ledger-textDark transition-colors"
              >
                {isSignUp ? 'Already have an account? Log in' : 'Don\'t have an account? Sign up'}
