// --- HELPERS ---

export const getWeekId = (date: Date = new Date()): string => {
  // ISO-8601 week number (Starts Monday), but business logic says Sunday->Saturday.
  // We'll construct a custom ID based on Sunday-start.
  const d = new Date(date);
  d.setHours(0,0,0,0);
  // Rewind to Sunday
  d.setDate(d.getDate() - d.getDay());

  // Format: YYYY-Www (e.g., 2024-W05) based on the Sunday date
  // Using simple YYYY-MM-DD of the Sunday is actually safer and easier to query/sort
  // Let's use YYYY-MM-DD of the Sunday. It's unique and sortable.
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

export const getTodayStr = () => {
    const d = new Date();
    const year = d.getFullYear();
    const month = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
};

// --- TYPES ---

export interface FirestoreHabit {
  id: string;
  name: string;
  status: 'active' | 'archived';
  sortOrder: number;
  createdAt: any;
}

export interface HabitSetVersion {
  weekId: string;
  habitIdsOrdered: string[];
  createdAt: any;
}

export interface DailyLogDoc {
  date: string;
  weekId: string;
  setVersionId: string;
  mask: number;
  updatedAt: any;
}

export interface WeekSummaryDoc {
  weekId: string;
  daysPresent: number;
  totalCompletedChecks: number;
  totalPossibleChecks: number;
  repairsUsed: number;
  updatedAt: any;
}

// --- CORE ACTIONS ---

// 1. Ensure a Habit Version exists for the current week
export const ensureWeekInitialized = async (userId: string, weekId: string) => {
  const versionRef = doc(db, `users/${userId}/habitSetVersions`, weekId);
  const versionSnap = await getDoc(versionRef);

  if (!versionSnap.exists()) {
    // Need to create one from active habits
    const habitsRef = collection(db, `users/${userId}/habits`);
    const q = query(habitsRef, where("status", "==", "active"));
    const snapshot = await getDocs(q);

    let activeHabits = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as FirestoreHabit));
    // Sort by sortOrder
    activeHabits.sort((a, b) => a.sortOrder - b.sortOrder);

    const habitIdsOrdered = activeHabits.map(h => h.id);

    // Create the version
    await setDoc(versionRef, {
      weekId,
      habitIdsOrdered,
      createdAt: serverTimestamp()
    });

    // Also initialize empty WeekSummary
    const summaryRef = doc(db, `users/${userId}/weeks`, weekId);
    await setDoc(summaryRef, {
      weekId,
      daysPresent: 0,
      totalCompletedChecks: 0,
      totalPossibleChecks: 0,
      repairsUsed: 0,
      updatedAt: serverTimestamp()
    }, { merge: true }); // Merge just in case
  }
};

// 2. Toggle a Habit
export const toggleHabitCompletion = async (
  userId: string, 
  habitId: string, 
  dateStr: string
) => {
  const weekId = getWeekId(new Date(dateStr));
  const todayStr = getTodayStr();

  // Rules
  const isPast = dateStr < todayStr;
  const isFuture = dateStr > todayStr;
  if (isFuture) return;

  await runTransaction(db, async (transaction) => {
    // A. Get Version to find index
    const versionRef = doc(db, `users/${userId}/habitSetVersions`, weekId);
    const versionSnap = await transaction.get(versionRef);
    if (!versionSnap.exists()) throw new Error("Week not initialized");

    const versionData = versionSnap.data() as HabitSetVersion;
    const index = versionData.habitIdsOrdered.indexOf(habitId);

    if (index === -1) {
      // Habit not in this week's version (maybe added mid-week, so it's not active yet)
      throw new Error("Habit not active for this week");
    }

    // B. Get Daily Log
    const logRef = doc(db, `users/${userId}/dailyLogs`, dateStr);
    const logSnap = await transaction.get(logRef);

    let mask = 0;
    if (logSnap.exists()) {
      mask = logSnap.data().mask || 0;
    }

    // C. Get Week Summary (Cache)
    const summaryRef = doc(db, `users/${userId}/weeks`, weekId);
    const summarySnap = await transaction.get(summaryRef);
    if (!summarySnap.exists()) throw new Error("Week summary missing");
    const summaryData = summarySnap.data() as WeekSummaryDoc;

    // D. Calculate Toggle
    const bit = 1 << index;
    const isCompleted = (mask & bit) !== 0;
    const newMask = mask ^ bit; // Toggle
    const isNowCompleted = (newMask & bit) !== 0;

    // E. Repair Logic
    let newRepairsUsed = summaryData.repairsUsed || 0;

    if (isPast) {
      if (isNowCompleted) {
        // Turning ON a past day -> Use Token
        if (newRepairsUsed >= 3) {
            throw new Error("No repair tokens remaining");
        }
        newRepairsUsed++;
      } else {
        // Turning OFF a past day -> Refund Token
        // NOTE: Simplification. We assume unchecking a past day refunds a token 
        // regardless of whether it was originally checked on-time or late.
        // This is a trade-off for not storing "isLate" per bit.
        newRepairsUsed = Math.max(0, newRepairsUsed - 1);
      }
    }

    // F. Update Cache Counts
    // If we created a new log (was empty), increment daysPresent
    let newDaysPresent = summaryData.daysPresent;
    if (!logSnap.exists()) {
        newDaysPresent++;
    } else if (newMask === 0) {
        // If we toggled off the LAST bit, strictly speaking the day is still "present" in logs
        // but has 0 completion. We leave daysPresent alone usually, or handle "empty" logs.
        // Let's keep simple: once a log exists, day is present.
    }

    let newTotalCompleted = summaryData.totalCompletedChecks;
    if (isNowCompleted) newTotalCompleted++;
    else newTotalCompleted--;

    // Recalculate possible checks based on version size * daysPresent
    // This is a bit tricky if daysPresent changes. 
    // Easier: Just add version length to potential when a new day is touched?
    // Actually, simpler metric: totalPossibleChecks = (daysPresent * versionData.habitIdsOrdered.length)
    // We update this dynamically.
    const habitsCount = versionData.habitIdsOrdered.length;
    const newTotalPossible = newDaysPresent * habitsCount;

    // G. Writes
    transaction.set(logRef, {
      date: dateStr,
      weekId,
      setVersionId: weekId, // Using weekId as version ID for simplicity
      mask: newMask,
      updatedAt: serverTimestamp()
    }, { merge: true });

    transaction.update(summaryRef, {
      daysPresent: newDaysPresent,
      totalCompletedChecks: newTotalCompleted,
      totalPossibleChecks: newTotalPossible,
      repairsUsed: newRepairsUsed,
      updatedAt: serverTimestamp()
    });
  });
};

// 3. Manage Habits (CRUD)
export const createHabit = async (userId: string, name: string) => {
    const habitsRef = collection(db, `users/${userId}/habits`);
    // Get count for sort order
    const snapshot = await getDocs(habitsRef);
    const count = snapshot.size;

    const newDoc = doc(habitsRef);
    await setDoc(newDoc, {
        name,
        status: 'active',
        sortOrder: count,
        createdAt: serverTimestamp()
    });
};

export const updateHabit = async (userId: string, habitId: string, changes: Partial<FirestoreHabit>) => {
    const ref = doc(db, `users/${userId}/habits`, habitId);
    await updateDoc(ref, changes);
};

export const reorderUserHabits = async (userId: string, orderedHabits: FirestoreHabit[]) => {
    const batch = writeBatch(db);
    orderedHabits.forEach((h, index) => {
        const ref = doc(db, `users/${userId}/habits`, h.id);
        batch.update(ref, { sortOrder: index });
    });
    await batch.commit();
};

