export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Local state mirrors for UI
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [weekSummary, setWeekSummary] = useState<any>(null);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);
  const [weeklySnapshot, setWeeklySnapshot] = useState<HabitSnapshot[]>([]);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        // Reset to default if logged out
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners (Only when user is logged in)
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentWeekId = getWeekId();

    // A. Ensure Week Initialized
    ensureWeekInitialized(userId, currentWeekId).then(() => {
        setIsLoading(false);
    }).catch(err => {
        console.error("Failed to init week", err);
        setIsLoading(false);
    });

    // B. Listen to Habits (The Master List)
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          isActive: data.status === 'active',
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // C. Listen to Current Week's Version (To build the Snapshot)
    const versionRef = doc(db, `users/${userId}/habitSetVersions`, currentWeekId);
    const unsubVersion = onSnapshot(versionRef, (docSnap) => {
        if (docSnap.exists()) {
            const data = docSnap.data();
            const orderedIds = data.habitIdsOrdered as string[];

            // We need to map these IDs back to names from the Habits collection
            // We rely on the 'habits' state being up to date, or we can fetch.
            // Since onSnapshot is async, habits might not be ready. 
            // We will derive `weeklySnapshot` in a separate effect or memo.
            // For now, store the IDs.
        }
    });

    // D. Listen to Daily Logs (Real-time sync of current week/month)
    // Querying all logs for now (MVP). Optimization: Query only last 365 days.
    const logsQuery = query(collection(db, `users/${userId}/dailyLogs`)); 
    const unsubLogs = onSnapshot(logsQuery, (snapshot) => {
       // We need to decode the masks!
       // This requires knowing the version for each log.
       // COMPLEXITY: Each log has `weekId`. We need the `habitSetVersion` for that weekId to decode.
       // SIMPLIFICATION: We will fetch versions on demand or cache them?
       // For MVP: We assume most logs are current week.
       // Actually, to display history, we need the version for that history.

       // Strategy: Just store the raw mask in state, and decode it at the View layer?
       // No, `DailyLog` type expects `completedHabitIds`.
       // We'll do a simple trick: We fetch the `HabitVersion` for the log's week.

       // For now, let's map the docs to an intermediate structure
       const rawLogs = snapshot.docs.map(d => ({...d.data(), id: d.id}));

       // We need to resolve these async.
       resolveLogs(userId, rawLogs).then(decodedLogs => {
           setLogs(decodedLogs);
       });
    });

    // E. Listen to User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
        } else {
            // Create default user doc
            setDoc(userRef, { theme: 'dark', isOnboarded: false }, { merge: true });
        }
    });

    // F. Listen to Week Summary (for repairs)
    const summaryRef = doc(db, `users/${userId}/weeks`, currentWeekId);
    const unsubSummary = onSnapshot(summaryRef, (docSnap) => {
        if(docSnap.exists()) {
            setWeekSummary(docSnap.data());
        }
    });

    return () => {
      unsubHabits();
      unsubVersion();
      unsubLogs();
      unsubUser();
      unsubSummary();
    };
  }, [user]);

  // Derived: Construct Weekly Snapshot from Habits + Current Week Version logic
  // Actually, checking `habitSetVersions` is safer.
  useEffect(() => {
      if(!user || habits.length === 0) return;
      const currentWeekId = getWeekId();

      const fetchVersion = async () => {
          const snap = await getDoc(doc(db, `users/${user.uid}/habitSetVersions`, currentWeekId));
          if(snap.exists()) {
              const ids = snap.data().habitIdsOrdered as string[];
              const snapshot: HabitSnapshot[] = ids.map(id => {
                  const h = habits.find(h => h.id === id);
                  return h ? { id: h.id, name: h.name } : null;
              }).filter(Boolean) as HabitSnapshot[];
              setWeeklySnapshot(snapshot);
          }
      };
      fetchVersion();
  }, [habits, user]);

  const resolveLogs = async (userId: string, rawLogs: any[]): Promise<DailyLog[]> => {
      // Group by weekId to batch fetch versions
      const versionsNeeded = new Set(rawLogs.map(l => l.weekId));
      const versionMap: Record<string, string[]> = {};

      await Promise.all(Array.from(versionsNeeded).map(async (wid) => {
          const vSnap = await getDoc(doc(db, `users/${userId}/habitSetVersions`, wid));
          if(vSnap.exists()) {
              versionMap[wid] = vSnap.data().habitIdsOrdered;
          }
      }));

      return rawLogs.map(l => {
          const orderedIds = versionMap[l.weekId] || [];
          const completedHabitIds: string[] = [];
          const mask = l.mask;

          orderedIds.forEach((hid, index) => {
              if ((mask & (1 << index)) !== 0) {
                  completedHabitIds.push(hid);
              }
          });

          return {
              date: l.date,
              completedHabitIds,
              repairedHabitIds: [] // We aren't storing this bit-level detail anymore in mask model
          };
      });
  };

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      try {
          await toggleHabitCompletion(user.uid, habitId, date);
      } catch (e: any) {
          alert(e.message);
      }
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await updateHabit(user.uid, id, { name });
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await updateHabit(user.uid, id, { status: 'archived' });
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      await updateHabit(user.uid, id, { status: 'active' });
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.isActive);
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);

      // We need to map this back to full list logic if we want to persist sortOrder properly
      // For MVP, just update sortOrder of all active habits
      await reorderUserHabits(user.uid, newActive);
  };

  const completeOnboarding = async () => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { isOnboarded: true }, { merge: true });
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const resetData = () => {
      if(confirm("This cannot be undone. Contact support to fully wipe data.")) {
         // Placeholder
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME EFFECT ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );

    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS ---
  const calculateStats = () => {
      // Simplified client-side stats from loaded logs
      // Ideally, we'd use the `WeekSummary` cache documents for this
      const todayStr = getTodayStr();
      const totalLoggedDays = logs.length;

      // Streak Logic
      let currentStreak = 0;
      const sortedDates = logs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));

          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      const activeCount = weeklySnapshot.length || 1;
      const perfectDays = logs.filter(l => l.completedHabitIds.length >= activeCount).length;

      // Weekly Score from Cache
      let weeklyScore = 0;
      if (weekSummary && weekSummary.totalPossibleChecks > 0) {
          weeklyScore = weekSummary.totalCompletedChecks / weekSummary.totalPossibleChecks;
      }

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS, // Achievements logic temporarily simplified
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: weekSummary ? (3 - (weekSummary.repairsUsed || 0)) : 3,
      lastTokenReset: '',
      dataYear: new Date().getFullYear(),
      weeklySnapshot
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      completeOnboarding, 
      setTheme, 
      resetData, 
      exportData,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              // Simple last 7 days calculation
              const count = logs.filter(l => l.completedHabitIds.includes(habitId)).length; // naive
              return 0; // TODO implement robust per-habit stats using cache
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

