// Create a new snapshot of active habits. Called whenever habits change (Add/Archive/Reorder)
export const createHabitSnapshot = async (userId: string) => {
    const habitsRef = collection(db, `users/${userId}/habits`);
    const q = query(habitsRef, where("status", "==", "active"));
    const snapshot = await getDocs(q);

    let activeHabits = snapshot.docs.map(d => ({ id: d.id, ...d.data() } as FirestoreHabit));
    activeHabits.sort((a, b) => a.sortOrder - b.sortOrder);
    const habitIdsOrdered = activeHabits.map(h => h.id);

    // Create a new version doc with auto-ID
    const versionsRef = collection(db, `users/${userId}/habitSetVersions`);
    const newVersionRef = doc(versionsRef);

    await setDoc(newVersionRef, {
        habitIdsOrdered,
        createdAt: serverTimestamp()
    });

    return newVersionRef.id;
};

// Helper to get the most recent version
const getLatestVersion = async (userId: string): Promise<HabitSetVersion | null> => {
    const versionsRef = collection(db, `users/${userId}/habitSetVersions`);
    const q = query(versionsRef, orderBy('createdAt', 'desc'), limit(1));
    const snap = await getDocs(q);
    if (snap.empty) return null;
    return { id: snap.docs[0].id, ...snap.docs[0].data() } as HabitSetVersion;
};

// Toggle Habit Logic (The Core Complex Logic)
export const toggleHabitCompletion = async (
  userId: string, 
  habitId: string, 
  dateStr: string
) => {
  const weekId = getWeekId(new Date(dateStr));
  const todayStr = getTodayStr();

  // Rules
  const isPast = dateStr < todayStr;
  const isFuture = dateStr > todayStr;
  if (isFuture) return;

  await runTransaction(db, async (transaction) => {
    // 1. Get Log
    const logRef = doc(db, `users/${userId}/dailyLogs`, dateStr);
    const logSnap = await transaction.get(logRef);
    let logData = logSnap.exists() ? logSnap.data() as DailyLogDoc : null;

    // 2. Determine Version
    let versionId = logData?.setVersionId;

    if (!versionId) {
        // New log: Use latest version
        const versionsRef = collection(db, `users/${userId}/habitSetVersions`);
        const q = query(versionsRef, orderBy('createdAt', 'desc'), limit(1));
        const vSnap = await getDocs(q); // Note: Transactional query requires strict rules, using non-transactional read here for MVP or we'd need to include in transaction
        // Firestore transactions require reads to come before writes.
        // We can query inside if we treat it as a read.
        if (vSnap.empty) {
            // Edge case: User has no versions yet (shouldn't happen if initialized).
            // Auto-create one?
            throw new Error("No habit versions found. Please add a habit first.");
        }
        versionId = vSnap.docs[0].id;
    }

    // 3. Get Version Data
    const versionRef = doc(db, `users/${userId}/habitSetVersions`, versionId);
    const versionSnap = await transaction.get(versionRef);
    if (!versionSnap.exists()) throw new Error("Version data missing");

    const versionData = versionSnap.data() as HabitSetVersion;
    const index = versionData.habitIdsOrdered.indexOf(habitId);

    if (index === -1) {
       // The user is trying to toggle a habit that DOES NOT EXIST in the version associated with this log.
       // E.g. They added "Read" today, but are viewing a log from yesterday that uses an old version.
       // We must block this to preserve history integrity.
       throw new Error("This habit did not exist on this date.");
    }

    // 4. Calculate Mask
    let mask = logData?.mask || 0;
    const bit = 1 << index;
    const isCompleted = (mask & bit) !== 0;
    const newMask = mask ^ bit; // Toggle

    // 5. Repair Logic (Distinct Days)
    const summaryRef = doc(db, `users/${userId}/weeks`, weekId);
    const summarySnap = await transaction.get(summaryRef);
    let repairedDates: string[] = [];
    if (summarySnap.exists()) {
        repairedDates = summarySnap.data().repairedDates || [];
    }

    if (isPast) {
        // If we are modifying a past date
        // Check if this date is already "paid for"
        if (!repairedDates.includes(dateStr)) {
            // Not paid for yet. Can we pay?
            if (repairedDates.length >= 3) {
                throw new Error("No repairs remaining this week.");
            }
            // Pay for it
            repairedDates.push(dateStr);

            // Log Event
            const eventRef = doc(collection(db, `users/${userId}/weeks/${weekId}/repairEvents`));
            transaction.set(eventRef, {
                targetDate: dateStr,
                createdAt: serverTimestamp(),
                beforeMask: mask,
                afterMask: newMask
            });
        }
    }

    // 6. Write
    transaction.set(logRef, {
        date: dateStr,
        weekId,
        setVersionId: versionId,
        mask: newMask,
        updatedAt: serverTimestamp()
    }, { merge: true });

    transaction.set(summaryRef, {
        weekId,
        repairedDates,
        updatedAt: serverTimestamp()
    }, { merge: true });
  });
};

