// Dangerous: Recursive Delete
export const deleteUserAccount = async (userId: string) => {
    // 1. Delete Subcollections (Manual effort as client SDK can't wildcard delete)
    // We will delete known collections.
    const collections = ['habits', 'habitSetVersions', 'dailyLogs', 'weeks'];

    for (const colName of collections) {
        const colRef = collection(db, `users/${userId}/${colName}`);
        const snap = await getDocs(colRef);
        const batch = writeBatch(db);
        let counter = 0;

        for (const doc of snap.docs) {
            batch.delete(doc.ref);
            counter++;
            if (counter >= 400) { // Batch limit
                await batch.commit();
                counter = 0;
            }
        }
        if (counter > 0) await batch.commit();
    }

    // 2. Delete User Doc
    await deleteDoc(doc(db, 'users', userId));

    // 3. Delete Auth (Requires recent login usually, handled by UI re-auth if needed)
    if (auth.currentUser) {
        await deleteUser(auth.currentUser);
    }
};

