                    <h3 className="text-lg font-bold text-ledger-text dark:text-ledger-textDark">Select Theme</h3>
                    <button onClick={() => setShowThemeModal(false)} className="p-2 bg-gray-100 dark:bg-gray-800 rounded-full text-ledger-text dark:text-ledger-textDark">
                        <X size={16} />
                    </button>
                </div>

                <div className="space-y-2">
                    {themes.map(t => (
                        <button
                            key={t.id}
                            onClick={() => {
                                setTheme(t.id);
                                setShowThemeModal(false);
                            }}
                            className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${state.theme === t.id ? 'border-ledger-accent bg-ledger-accent/5' : 'border-gray-100 dark:border-gray-800 bg-transparent hover:bg-gray-50 dark:hover:bg-white/5'}`}
                        >
                            <div className="text-left">
                                <p className={`font-semibold ${state.theme === t.id ? 'text-ledger-accent' : 'text-ledger-text dark:text-ledger-textDark'}`}>{t.name}</p>
                                <p className="text-xs text-ledger-muted">{t.description}</p>
                            </div>
                            {state.theme === t.id && <Check size={18} className="text-ledger-accent" />}
                        </button>
                    ))}
                </div>
            </div>
        </div>
      )}

      {/* Delete Confirmation Modal */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
              <div className="bg-white dark:bg-[#1A1A1A] rounded-2xl p-6 max-w-sm w-full border border-gray-200 dark:border-gray-800">
                  <div className="flex items-center gap-3 text-red-600 mb-4">
                      <AlertTriangle size={24} />
                      <h3 className="text-lg font-bold">Delete Account?</h3>
                  </div>
                  <p className="text-ledger-text dark:text-ledger-textDark mb-6">
                      This action is permanent and cannot be undone. All your habits and history will be wiped from our servers immediately.
                  </p>
                  <div className="flex gap-3">
                      <button 
                        onClick={() => setShowDeleteModal(false)}
                        className="flex-1 py-3 font-medium text-ledger-text dark:text-ledger-textDark hover:bg-gray-100 dark:hover:bg-white/5 rounded-lg transition-colors"
                      >
                          Cancel
                      </button>
                      <button 
                        onClick={() => {
                            deleteAccount();
                            setShowDeleteModal(false);
                        }}
                        className="flex-1 py-3 font-medium bg-red-600 hover:bg-red-700 text-white rounded-lg transition-colors"
                      >
                          Delete
                      </button>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, MAX_HABITS, STATIC_ACHIEVEMENTS, Achievement, ThemeOption, HabitSnapshot } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    where, 
    orderBy, 
    onSnapshot, 
    doc, 
    getDoc, 
    getDocs,
    setDoc,
    limit 
} from 'firebase/firestore';
import { 
    createHabitSnapshot,
    getWeekId, 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    updateHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => void;
  toggleHabit: (habitId: string, date: string) => void;
  updateHabitName: (id: string, name: string) => void;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  completeOnboarding: () => void;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  lastTokenReset: new Date().toISOString().split('T')[0],
  dataYear: new Date().getFullYear(),
  weeklySnapshot: []
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Local state mirrors for UI
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairedDates, setRepairedDates] = useState<string[]>([]);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentWeekId = getWeekId();

    // A. Init Check (Ensure at least one version exists if we have active habits)
    // Removed strict week initialization. Version is created on habit change.

    // B. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, async (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          isActive: data.status === 'active',
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);

      // Check if we need to seed the very first version snapshot
      if (loadedHabits.length > 0) {
          const vRef = collection(db, `users/${userId}/habitSetVersions`);
          const q = query(vRef, limit(1));
          const snap = await getDocs(q);
          if (snap.empty) {
              await createHabitSnapshot(userId);
          }
      }
    });

    // C. Daily Logs
    const logsQuery = query(collection(db, `users/${userId}/dailyLogs`)); 
    const unsubLogs = onSnapshot(logsQuery, (snapshot) => {
       const rawLogs = snapshot.docs.map(d => ({...d.data(), id: d.id}));
       resolveLogs(userId, rawLogs).then(decodedLogs => {
           setLogs(decodedLogs);
       });
    });

    // D. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setDoc(userRef, { theme: 'dark', isOnboarded: false }, { merge: true });
            setIsLoading(false);
        }
    });

    // E. Week Summary (Repairs)
    const summaryRef = doc(db, `users/${userId}/weeks`, currentWeekId);
    const unsubSummary = onSnapshot(summaryRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setRepairedDates(data.repairedDates || []);
        } else {
            setRepairedDates([]);
        }
    });

    return () => {
      unsubHabits();
      unsubLogs();
      unsubUser();
      unsubSummary();
    };
  }, [user]);

  // Resolves masks into habit IDs by fetching the version doc referenced in the log
  const resolveLogs = async (userId: string, rawLogs: any[]): Promise<DailyLog[]> => {
      // Group by versionId to batch fetch
      const versionIds = new Set(rawLogs.map(l => l.setVersionId).filter(Boolean));
      const versionMap: Record<string, string[]> = {};

      await Promise.all(Array.from(versionIds).map(async (vid) => {
          // Optimization: Cache this in memory if possible, but Firestore client caches reads well.
          const vSnap = await getDoc(doc(db, `users/${userId}/habitSetVersions`, vid as string));
          if(vSnap.exists()) {
              versionMap[vid as string] = vSnap.data().habitIdsOrdered;
          }
      }));

      return rawLogs.map(l => {
          // If a log has no version ID (legacy?), assumes empty or handles gracefully
          const orderedIds = versionMap[l.setVersionId] || [];
          const completedHabitIds: string[] = [];
          const mask = l.mask;

          orderedIds.forEach((hid, index) => {
              if ((mask & (1 << index)) !== 0) {
                  completedHabitIds.push(hid);
              }
          });

          return {
              date: l.date,
              completedHabitIds,
              possibleHabitIds: orderedIds
          };
      });
  };

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      try {
          await toggleHabitCompletion(user.uid, habitId, date);
      } catch (e: any) {
          // Ideally use a toast here
          alert(e.message);
      }
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await updateHabit(user.uid, id, { name });
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await updateHabit(user.uid, id, { status: 'archived' });
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      await updateHabit(user.uid, id, { status: 'active' });
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.isActive);
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const completeOnboarding = async () => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { isOnboarded: true }, { merge: true });
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     // Kept for interface compatibility, basically mapped to deleteAccount or specific wipe
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account. You may need to re-login explicitly.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS ---
  const calculateStats = () => {
      const todayStr = getTodayStr();
      const totalLoggedDays = logs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = logs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days
      // Need to compare completed vs possible for each log
      const perfectDays = logs.filter(l => l.completedHabitIds.length > 0 && l.completedHabitIds.length === l.possibleHabitIds.length).length;

      // Weekly Score (Aggregated from Daily Denominators)
      // Logic: Sum of all checks in week / Sum of all possible checks in week
      const currentWeekId = getWeekId();
      // Filter logs for this week
      const weekLogs = logs.filter(l => {
          // Naive check: does log fall in this week?
          // We can use the weekId stored in the log if we had it in state, but we don't return it in resolveLogs currently.
          // Let's compute it.
          const lid = getWeekId(new Date(l.date));
          return lid === currentWeekId;
      });

      let wChecks = 0;
      let wPossible = 0;
      weekLogs.forEach(l => {
          wChecks += l.completedHabitIds.length;
          wPossible += l.possibleHabitIds.length;
      });

      // For days in current week that DON'T have logs yet, we assume the CURRENT active set
      // This is for the projection/score.
      // But for pure "past performance", we usually only count days that passed?
      // Let's stick to: Score = What you did / What you *could* have done (including today/past days of week).

      const weeklyScore = wPossible > 0 ? wChecks / wPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: 3 - repairedDates.length,
      lastTokenReset: '',
      dataYear: new Date().getFullYear(),
      weeklySnapshot: []
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      completeOnboarding, 
      setTheme, 
      resetData, 
      exportData,
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => 0
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
