    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => void;
  toggleHabit: (habitId: string, date: string) => void;
  updateHabitName: (id: string, name: string) => void;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  completeOnboarding: () => void;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  dataYear: new Date().getFullYear(),
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairedDates, setRepairedDates] = useState<string[]>([]);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentWeekId = getWeekId();

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs
    // MVP: Load all. Optimization: Load only last 365 days or current view range.
    const logsQuery = query(collection(db, `users/${userId}/dailyLogs`)); 
    const unsubLogs = onSnapshot(logsQuery, (snapshot) => {
       const loadedLogs: DailyLog[] = snapshot.docs.map(d => ({
           id: d.id,
           ...d.data()
       })) as unknown as DailyLog[];
       setLogs(loadedLogs);
    });

    // C. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setDoc(userRef, { theme: 'dark', isOnboarded: false }, { merge: true });
            setIsLoading(false);
        }
    });

    // D. Week Summary (Repairs)
    const summaryRef = doc(db, `users/${userId}/weeks`, currentWeekId);
    const unsubSummary = onSnapshot(summaryRef, (docSnap) => {
        if(docSnap.exists()) {
            setRepairedDates(docSnap.data().repairedDates || []);
        } else {
            setRepairedDates([]);
        }
    });

    return () => {
      unsubHabits();
      unsubLogs();
      unsubUser();
      unsubSummary();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      try {
          await toggleHabitCompletion(user.uid, habitId, date);
      } catch (e: any) {
          alert(e.message);
      }
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      // "Restore" creates a new habit with the same name to preserve history gaps
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const completeOnboarding = async () => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { isOnboarded: true }, { merge: true });
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();
      const currentWeekId = getWeekId();

      // Filter logs to those that have at least one check
      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      // We need to iterate dates for the current week to calculate weekly score precisely
      // Start of week
      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const dateStr = d.toISOString().split('T')[0];

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      // Perfect Days (over all time)
      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: 3 - repairedDates.length,
      dataYear: new Date().getFullYear(),
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      completeOnboarding, 
      setTheme, 
      resetData, 
      exportData,
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              // Naive last 7 days consistency
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const ds = d.toISOString().split('T')[0];
                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React from 'react';
import { useApp } from '../context/AppContext';
import { User, Check, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

export const Today: React.FC = () => {
  const { state, toggleHabit } = useApp();
  const navigate = useNavigate();

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const dayOfWeek = today.getDay();

  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    return {
        dateStr: d.toISOString().split('T')[0],
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: d.toISOString().split('T')[0] === todayStr,
        isFuture: d.toISOString().split('T')[0] > todayStr
    };
  });

  // Rows: Any habit that is Active OR was Active at some point during this week
  // But standard UI usually shows currently active habits.
  // The prompt says "Habit changes apply immediately... It appears immediately in the current week view for today onward."
  // This implies we display current Active habits.
  const displayHabits = state.habits.filter(h => h.status === 'active');

  // Stats Logic
  let totalCompleted = 0;
  let totalPotential = 0;

  displayHabits.forEach(h => {
      weekDays.forEach(day => {
          // Check applicability
          const isApplicable = day.dateStr >= h.activeFrom && (!h.inactiveFrom || day.dateStr < h.inactiveFrom);
          if (isApplicable) {
              totalPotential++;
              const log = state.logs.find(l => l.date === day.dateStr);
              if (log && log.checks[h.id]) {
                  totalCompleted++;
              }
          }
      });
  });

  const weeklyPercentage = totalPotential > 0 ? (totalCompleted / totalPotential) * 100 : 0;

  const handleToggle = (id: string, date: string, isFuture: boolean, isNA: boolean) => {
    if (isFuture || isNA) return;
    toggleHabit(id, date);
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative font-sans">
      {/* Header */}
      <header className="px-6 py-5 flex items-center justify-between sticky top-0 z-50 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl border-b border-ledger-border dark:border-ledger-borderDark">
        <div>
            <h1 className="text-base font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">
                Current Week
            </h1>
            <p className="text-xs text-ledger-muted mt-0.5 font-medium">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </p>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark hover:opacity-70 transition-opacity">
          <User size={22} strokeWidth={2} />
        </button>
      </header>

      {/* KPI Section */}
      <div className="px-6 py-6 border-b border-ledger-border dark:border-ledger-borderDark bg-white dark:bg-[#111111]">
         <div className="flex items-center justify-between">
             <div>
                <div className="text-4xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tight">
                    {Math.round(weeklyPercentage)}%
                </div>
                <div className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mt-1">
                    {totalCompleted} / {totalPotential} Checks
                </div>
             </div>

             <div className="flex flex-col items-end gap-1">
                 <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 dark:bg-white/10 rounded-md">
                    <Zap size={14} className="text-ledger-accent" fill="currentColor" />
                    <span className="text-xs font-bold text-ledger-text dark:text-ledger-textDark">{state.repairTokens}</span>
                 </div>
                 <span className="text-[10px] font-medium text-ledger-muted">Repair Days Left</span>
             </div>
         </div>
      </div>

      {/* Main Grid */}
      <div className="flex-1 overflow-auto no-scrollbar pb-24 relative bg-ledger-bg dark:bg-ledger-bgDark">
         <table className="border-collapse min-w-full">
            <thead className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark shadow-sm">
                <tr>
                    <th className="sticky left-0 top-0 z-50 bg-ledger-bg dark:bg-ledger-bgDark border-b border-r border-gray-100 dark:border-gray-800 px-4 py-4 text-left">
                        <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider whitespace-nowrap">Task</span>
                    </th>
                    {weekDays.map(d => (
                        <th key={d.dateStr} className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark border-b border-gray-100 dark:border-gray-800 px-2 py-4 min-w-[60px]">
                            <div className={`flex flex-col items-center justify-center gap-1.5 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                                <span className="text-[10px] font-bold uppercase tracking-wider">{d.label}</span>
                                <span className={`text-xs font-bold w-6 h-6 flex items-center justify-center rounded-full transition-colors ${d.isToday ? 'bg-ledger-accent text-white shadow-md' : 'bg-transparent text-inherit'}`}>
                                    {d.dayNum}
                                </span>
                            </div>
                        </th>
                    ))}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800/50">
                {displayHabits.map(habit => (
                    <tr key={habit.id} className="group bg-white dark:bg-ledger-bgDark">
                        <td className="sticky left-0 z-30 bg-white dark:bg-ledger-bgDark border-r border-gray-100 dark:border-gray-800 px-4 py-3 whitespace-nowrap">
                            <span className="text-sm font-semibold text-ledger-text dark:text-ledger-textDark">
                                {habit.name}
                            </span>
                        </td>

                        {weekDays.map(d => {
                             const log = state.logs.find(l => l.date === d.dateStr);
                             const isCompleted = log?.checks && log.checks[habit.id];

                             // N/A Logic: Date must be within Active Range
                             const isApplicable = d.dateStr >= habit.activeFrom && (!habit.inactiveFrom || d.dateStr < habit.inactiveFrom);
                             const isNA = !isApplicable;

                             // Styles
                             let cellContent = null;
                             let cellClass = "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-200 border-2 mx-auto";

                             if (d.isFuture) {
                                 cellClass += " border-transparent bg-gray-50 dark:bg-white/5 opacity-30 cursor-not-allowed";
                             } else if (isNA) {
                                 cellClass += " border-transparent bg-gray-100 dark:bg-white/5 cursor-not-allowed";
                                 cellContent = <div className="w-4 h-0.5 bg-gray-300 dark:bg-gray-700 rounded-full" />;
                             } else if (isCompleted) {
                                 cellClass += " border-ledger-accent bg-ledger-accent text-white shadow-sm";
                                 cellContent = <Check size={20} strokeWidth={4} />;
                             } else {
                                 // Empty but possible
                                 cellClass += " border-gray-200 dark:border-gray-800 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent/50";
                             }

                            return (
                                <td key={d.dateStr} className="px-2 py-2">
                                     <button
                                        onClick={() => handleToggle(habit.id, d.dateStr, d.isFuture, isNA)}
                                        disabled={d.isFuture || isNA}
                                        className="active:scale-95 transition-transform block w-full"
                                     >
                                         <div className={cellClass}>
                                             {cellContent}
                                         </div>
                                     </button>
                                </td>
                            );
                        })}
                    </tr>
                ))}
            </tbody>
         </table>
         {displayHabits.length === 0 && (
            <div className="p-8 text-center text-ledger-muted">
                No active habits. Go to Habits tab to add some.
            </div>
         )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { ChevronLeft, ChevronRight } from 'lucide-react';

type ViewMode = 'Year' | 'Month' | 'Week';

export const Progress: React.FC = () => {
  const { state } = useApp();
  const [view, setView] = useState<ViewMode>('Year');

  // Navigation States
  const [selectedWeekOffset, setSelectedWeekOffset] = useState(0); 
  const [selectedMonthOffset, setSelectedMonthOffset] = useState(0); 

  const today = new Date();
  const currentYear = today.getFullYear();

  // Helper: Is habit applicable on date?
  const isApplicable = (habitId: string, dateStr: string) => {
      const habit = state.habits.find(h => h.id === habitId);
      if (!habit) return false;
      return dateStr >= habit.activeFrom && (!habit.inactiveFrom || dateStr < habit.inactiveFrom);
  };

  const getWeekNumber = (d: Date) => {
      const date = new Date(Date.UTC(d.getFullYear(), d.getMonth(), d.getDate()));
      date.setUTCDate(date.getUTCDate() + 4 - (date.getUTCDay() || 7));
      const yearStart = new Date(Date.UTC(date.getUTCFullYear(), 0, 1));
      const weekNo = Math.ceil(( ( (date.getTime() - yearStart.getTime()) / 86400000) + 1) / 7);
      return weekNo - 1; 
  };

  const currentWeekIndex = getWeekNumber(today);

  // --- VIEW: YEAR ---
  const renderYearView = () => {
    const weeks = [];
    let d = new Date(currentYear, 0, 1);

    while (d.getDay() !== 0) {
        d.setDate(d.getDate() - 1);
    }

    for (let i = 0; i < 53; i++) {
        const weekStart = new Date(d);
        const weekEnd = new Date(d);
        weekEnd.setDate(weekEnd.getDate() + 6);

        const startStr = weekStart.toISOString().split('T')[0];
        const endStr = weekEnd.toISOString().split('T')[0];

        // Compute "Days Logged" (Any activity on that day)
        const logsInWeek = state.logs.filter(l => l.date >= startStr && l.date <= endStr);
        const activeDays = logsInWeek.filter(l => Object.keys(l.checks || {}).length > 0).length;

        const fillPercent = (activeDays / 7) * 100;

        weeks.push({ 
            id: i, 
            fillPercent, 
            startDate: weekStart,
            isCurrent: i === currentWeekIndex,
            weekNum: i + 1
        });

        d.setDate(d.getDate() + 7);
    }

    return (
        <div className="grid grid-cols-7 gap-3 px-2">
            {weeks.map((w) => (
                <button
                    key={w.id}
                    onClick={() => {
                        const offset = w.id - currentWeekIndex;
                        setSelectedWeekOffset(offset);
                        setView('Week');
                    }}
                    className={`aspect-square rounded-md border border-gray-200 dark:border-gray-800 relative overflow-hidden flex items-end justify-center ${w.isCurrent ? 'ring-2 ring-ledger-accent ring-offset-2 dark:ring-offset-ledger-bgDark' : ''}`}
                >
                    <div 
                        className="absolute inset-x-0 bottom-0 bg-ledger-accent transition-all duration-700 ease-out opacity-80"
                        style={{ height: `${Math.max(w.fillPercent, 0)}%` }}
                    />
                    <span className="relative z-10 text-[10px] font-bold text-ledger-text dark:text-ledger-textDark mix-blend-difference mb-1">
                        {w.weekNum}
                    </span>
                </button>
            ))}
        </div>
    );
  };

  // --- VIEW: MONTH ---
  const renderMonthView = () => {
    const targetDate = new Date(today.getFullYear(), today.getMonth() + selectedMonthOffset, 1);
    const targetMonth = targetDate.getMonth();
    const targetYear = targetDate.getFullYear();

    const minOffset = -today.getMonth();
    const maxOffset = 11 - today.getMonth();
    const isPrevDisabled = selectedMonthOffset <= minOffset;
    const isNextDisabled = selectedMonthOffset >= maxOffset;

    const daysInMonth = new Date(targetYear, targetMonth + 1, 0).getDate();
    const firstDayIndex = new Date(targetYear, targetMonth, 1).getDay();

    const days = Array.from({ length: daysInMonth }, (_, i) => {
        const d = new Date(targetYear, targetMonth, i + 1);
        const dateStr = d.toISOString().split('T')[0];
        const log = state.logs.find(l => l.date === dateStr);
        const hasLog = log && Object.keys(log.checks || {}).length > 0;
        const isToday = dateStr === today.toISOString().split('T')[0];
        return { dateStr, dayNum: i + 1, hasLog, isToday };
    });

    const blanks = Array.from({ length: firstDayIndex }, (_, i) => i);

    return (
        <div className="px-4">
             <div className="flex items-center justify-between mb-6 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p - 1)} 
                    disabled={isPrevDisabled}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark uppercase tracking-wide">
                      {targetDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedMonthOffset(p => p + 1)} 
                    disabled={isNextDisabled} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

             <div className="grid grid-cols-7 gap-3">
                {['S','M','T','W','T','F','S'].map((d, i) => (
                    <div key={i} className="text-center text-[10px] font-bold text-ledger-muted uppercase mb-2">{d}</div>
                ))}

                {blanks.map(i => <div key={`blank-${i}`} />)}

                {days.map(d => (
                    <div 
                        key={d.dateStr}
                        className={`aspect-square rounded-lg flex items-center justify-center text-sm font-semibold transition-all
                            ${d.hasLog 
                                ? 'bg-ledger-accent text-white shadow-sm' 
                                : 'bg-white dark:bg-ledger-surfaceDark text-ledger-muted border border-gray-100 dark:border-gray-800'}
                            ${d.isToday ? 'ring-2 ring-ledger-accent ring-offset-1 dark:ring-offset-ledger-bgDark' : ''}
                        `}
                    >
                        {d.dayNum}
                    </div>
                ))}
             </div>
        </div>
    );
  };

  // --- VIEW: WEEK ---
  const renderWeekView = () => {
      const startOfSelectedWeek = new Date(today);
      const day = startOfSelectedWeek.getDay();
      const diff = startOfSelectedWeek.getDate() - day + (selectedWeekOffset * 7);
      startOfSelectedWeek.setDate(diff);

      const weekDays = Array.from({ length: 7 }, (_, i) => {
          const d = new Date(startOfSelectedWeek);
          d.setDate(d.getDate() + i);
          const dateStr = d.toISOString().split('T')[0];

          let possible = 0;
          let completed = 0;

          state.habits.forEach(h => {
              if (isApplicable(h.id, dateStr)) {
                  possible++;
                  const log = state.logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      completed++;
                  }
              }
          });

          const pct = possible > 0 ? (completed / possible) * 100 : 0;
          const isDifferentYear = d.getFullYear() !== currentYear;

          return { 
              label: d.toLocaleDateString('en-US', { weekday: 'narrow' }), 
              pct, 
              dateStr,
              isDifferentYear
          };
      });

      const endOfSelectedWeek = new Date(startOfSelectedWeek);
      endOfSelectedWeek.setDate(endOfSelectedWeek.getDate() + 6);

      const isEarliestWeek = selectedWeekOffset <= -currentWeekIndex;

      return (
          <div className="px-4">
              <div className="flex items-center justify-between mb-8 bg-white dark:bg-ledger-surfaceDark p-3 rounded-lg border border-gray-100 dark:border-gray-800 shadow-sm">
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p - 1)} 
                    disabled={isEarliestWeek}
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronLeft size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
                  <span className="text-sm font-bold text-ledger-text dark:text-ledger-textDark">
                      {startOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfSelectedWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                  </span>
                  <button 
                    onClick={() => setSelectedWeekOffset(p => p + 1)} 
                    disabled={selectedWeekOffset >= 0} 
                    className="p-2 hover:bg-gray-100 dark:hover:bg-white/5 rounded-full disabled:opacity-30 disabled:cursor-not-allowed"
                  >
                      <ChevronRight size={20} className="text-ledger-text dark:text-ledger-textDark" />
                  </button>
              </div>

              <div className="h-64 flex items-end justify-between gap-3 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-border dark:border-ledger-borderDark">
                  {weekDays.map((d, i) => (
                      <div key={i} className={`flex flex-col items-center gap-2 flex-1 h-full justify-end group ${d.isDifferentYear ? 'opacity-30 grayscale' : ''}`}>
                          <div className="w-full bg-gray-100 dark:bg-white/5 rounded-t-sm relative h-full flex items-end overflow-hidden">
                              <div 
                                  className={`w-full bg-ledger-accent transition-all duration-500 ease-out rounded-t-sm ${d.isDifferentYear ? 'bg-gray-400' : ''}`}
                                  style={{ height: `${Math.max(d.pct, 4)}%` }} 
                              />
                          </div>
                          <span className="text-xs font-bold text-ledger-muted uppercase">{d.label}</span>
                      </div>
                  ))}
              </div>
          </div>
      );
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-4 overflow-y-auto no-scrollbar">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark px-2">Progress</h1>
      </header>

      {/* View Switcher */}
      <div className="flex p-1 bg-gray-200 dark:bg-[#1A1A1A] rounded-xl mb-8 mx-2">
          {(['Year', 'Month', 'Week'] as ViewMode[]).map(mode => (
              <button 
                key={mode}
                onClick={() => {
                    setView(mode);
                    if(mode === 'Week') setSelectedWeekOffset(0);
                    if(mode === 'Month') setSelectedMonthOffset(0);
                }}
                className={`flex-1 py-2 text-xs font-bold uppercase tracking-wide rounded-lg transition-all ${view === mode ? 'bg-white dark:bg-ledger-surfaceDark text-ledger-text dark:text-ledger-textDark shadow-sm' : 'text-ledger-muted'}`}
              >
                  {mode}
              </button>
          ))}
      </div>

      <div className="flex-1 animate-fade-in">
          {view === 'Year' && (
              <div>
                  <h3 className="px-2 text-xs font-bold text-ledger-muted uppercase tracking-wider mb-4">{currentYear} Overview</h3>
                  {renderYearView()}
              </div>
          )}
          {view === 'Month' && renderMonthView()}
          {view === 'Week' && renderWeekView()}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { MAX_HABITS } from '../types';
import { Trash2, Archive, ArrowUp, ArrowDown, RotateCcw, Plus, Activity } from 'lucide-react';
import { Button } from '../components/Button';

export const Habits: React.FC = () => {
  const { state, addHabit, updateHabitName, archiveHabit, restoreHabit, reorderHabits, stats } = useApp();
  const [newHabitName, setNewHabitName] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  const activeHabits = state.habits.filter(h => h.status === 'active');
  const archivedHabits = state.habits.filter(h => h.status === 'archived');
  const isLimitReached = activeHabits.length >= MAX_HABITS;

  const handleAdd = () => {
    if (!newHabitName.trim()) return;
    addHabit(newHabitName.trim());
    setNewHabitName('');
    setIsAdding(false);
  };

  const moveHabit = (index: number, direction: 'up' | 'down') => {
    const newIndex = direction === 'up' ? index - 1 : index + 1;
    if (newIndex >= 0 && newIndex < activeHabits.length) {
        reorderHabits(index, newIndex);
    }
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6 overflow-y-auto">
      <header className="mb-6 flex justify-between items-center">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">Habits</h1>
        <span className="text-sm font-medium text-ledger-muted bg-gray-200 dark:bg-gray-800 px-2 py-1 rounded">
            {activeHabits.length} / {MAX_HABITS}
        </span>
      </header>

      {/* Active List */}
      <div className="space-y-4 mb-8">
        {activeHabits.map((habit, index) => {
          const consistency = stats.getHabitConsistency(habit.id);

          return (
            <div key={habit.id} className="bg-white dark:bg-ledger-surfaceDark p-4 rounded-xl shadow-sm border border-ledger-border dark:border-ledger-borderDark flex flex-col gap-3 group">
              <div className="flex items-center justify-between">
                <div className="flex-1">
                    <input 
                        className="w-full bg-transparent font-medium text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-b border-ledger-accent"
                        value={habit.name}
                        onChange={(e) => updateHabitName(habit.id, e.target.value)}
                        maxLength={17}
                    />
                </div>
                <div className="flex items-center gap-1 ml-4 opacity-50 group-hover:opacity-100 transition-opacity">
                    <div className="flex flex-col mr-2">
                        <button 
                            onClick={() => moveHabit(index, 'up')}
                            disabled={index === 0}
                            className="p-1 hover:text-ledger-accent disabled:opacity-20"
                        >
                            <ArrowUp size={14} />
                        </button>
                        <button 
                            onClick={() => moveHabit(index, 'down')}
                            disabled={index === activeHabits.length - 1}
                            className="p-1 hover:text-ledger-accent disabled:opacity-20"
                        >
                            <ArrowDown size={14} />
                        </button>
                    </div>
                    <button 
                        onClick={() => archiveHabit(habit.id)}
                        className="p-2 hover:bg-gray-100 dark:hover:bg-gray-800 rounded text-ledger-muted hover:text-red-500"
                        title="Archive"
                    >
                        <Archive size={18} />
                    </button>
                </div>
              </div>

              <div className="flex items-center gap-2 pt-2 border-t border-gray-50 dark:border-gray-800">
                  <Activity size={12} className="text-ledger-muted" />
                  <span className="text-[10px] uppercase font-semibold text-ledger-muted tracking-wide">
                    7-Day Consistency: <span className="text-ledger-accent">{Math.round(consistency)}%</span>
                  </span>
              </div>
            </div>
          );
        })}

        {isAdding ? (
            <div className="flex items-center gap-2 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-accent animate-fade-in">
                <input 
                    autoFocus
                    value={newHabitName}
                    onChange={e => setNewHabitName(e.target.value)}
                    placeholder="Habit name..."
                    className="flex-1 bg-transparent focus:outline-none text-ledger-text dark:text-ledger-textDark"
                    onKeyDown={e => e.key === 'Enter' && handleAdd()}
                    maxLength={17}
                />
                <button onClick={handleAdd} className="text-sm font-semibold text-ledger-accent">Save</button>
            </div>
        ) : (
             <Button 
                variant="secondary" 
                fullWidth 
                onClick={() => setIsAdding(true)}
                disabled={isLimitReached}
                className="border-dashed"
            >
                <Plus size={18} className="mr-2" />
                {isLimitReached ? 'Limit reached' : 'Add habit'}
            </Button>
        )}
      </div>

      {/* Archived Section */}
      {archivedHabits.length > 0 && (
        <div className="mt-auto pt-8">
            <h3 className="text-xs font-semibold uppercase text-ledger-muted tracking-wider mb-4">Archived</h3>
            <div className="space-y-2">
                {archivedHabits.map(habit => (
                    <div key={habit.id} className="flex items-center justify-between p-3 rounded-lg border border-transparent hover:border-ledger-border dark:hover:border-ledger-borderDark transition-colors">
                        <span className="text-ledger-muted line-through">{habit.name}</span>
                        <button 
                            onClick={() => restoreHabit(habit.id)}
                            disabled={isLimitReached}
                            className="p-2 text-ledger-accent hover:bg-green-50 dark:hover:bg-green-900/10 rounded flex items-center gap-1 text-sm disabled:opacity-30"
                        >
                            <RotateCcw size={14} />
                            Restore
                        </button>
                    </div>
                ))}
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { X, CheckCircle, XCircle } from 'lucide-react';

export const History: React.FC = () => {
  const { state } = useApp();
  const [selectedDate, setSelectedDate] = useState<string | null>(null);

  // Generate last 30 days
  const today = new Date();
  const days = Array.from({ length: 30 }, (_, i) => {
    const d = new Date(today);
    d.setDate(d.getDate() - (29 - i));
    return d.toISOString().split('T')[0];
  });

  const getLogForDate = (date: string) => state.logs.find(l => l.date === date);

  const getDayScore = (date: string) => {
    const log = getLogForDate(date);
    // Find active habits AT THAT TIME is hard without history tracking of habit activation. 
    // MVP Assumption: Score based on CURRENT active habits to keep data model simple, 
    // or just raw count. Let's use current active habits count as denominator.
    const activeCount = state.habits.filter(h => h.status === 'active').length;
    if (activeCount === 0) return 0;

    const completedCount = Object.keys(log?.checks || {}).filter(id => {
         // Filter to ensure we only count habits that are still in the system (even if archived, they exist)
         return state.habits.find(h => h.id === id);
    }).length || 0;

    return completedCount / activeCount;
  };

  const totalLoggedDays = state.logs.length;
  // Simple average calc
  const averageScore = state.logs.reduce((acc, log) => {
     const activeCount = state.habits.filter(h => h.status === 'active').length || 1;
     const completedCount = Object.keys(log.checks || {}).length;
     return acc + (completedCount / activeCount);
  }, 0) / (totalLoggedDays || 1);


  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark p-6">
      <header className="mb-6">
        <h1 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark">History</h1>
      </header>

      {/* 30 Day Grid */}
      <div className="grid grid-cols-7 gap-2 mb-8">
        {days.map((date) => {
          const score = getDayScore(date);
          const isToday = date === today.toISOString().split('T')[0];

          let bgColor = 'bg-gray-200 dark:bg-[#262626]'; // Default 0%
          if (score >= 1) bgColor = 'bg-ledger-accent';
          else if (score > 0) bgColor = 'bg-ledger-accent opacity-50'; // Simplification for partial

          return (
            <button
              key={date}
              onClick={() => setSelectedDate(date)}
              className={`aspect-square rounded-sm ${bgColor} relative hover:opacity-80 transition-opacity`}
            >
                {isToday && <div className="absolute top-1 right-1 w-1.5 h-1.5 bg-white rounded-full shadow-sm" />}
            </button>
          );
        })}
      </div>

      {/* Summary */}
      <div className="bg-white dark:bg-ledger-surfaceDark rounded-lg p-6 border border-ledger-border dark:border-ledger-borderDark shadow-sm">
        <h3 className="text-sm font-medium text-ledger-muted uppercase tracking-wider mb-4">This Month</h3>
        <div className="flex justify-between items-end">
            <div>
                <p className="text-3xl font-semibold text-ledger-text dark:text-ledger-textDark">{Math.round(averageScore * 100)}%</p>
                <p className="text-sm text-ledger-muted mt-1">Consistency</p>
            </div>
            <div className="text-right">
                <p className="text-3xl font-semibold text-ledger-text dark:text-ledger-textDark">{totalLoggedDays}</p>
                <p className="text-sm text-ledger-muted mt-1">Days logged</p>
            </div>
        </div>
      </div>

      {/* Bottom Sheet Modal */}
      {selectedDate && (
        <div className="absolute inset-0 z-50 flex items-end justify-center bg-black/20 backdrop-blur-sm transition-opacity" onClick={() => setSelectedDate(null)}>
          <div 
            className="w-full bg-white dark:bg-[#1A1A1A] rounded-t-2xl p-6 animate-slide-up shadow-2xl" 
            onClick={e => e.stopPropagation()}
          >
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-semibold text-ledger-text dark:text-ledger-textDark">
                {new Date(selectedDate).toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
              </h3>
              <button onClick={() => setSelectedDate(null)} className="p-2 bg-gray-100 dark:bg-gray-800 rounded-full">
                <X size={16} />
              </button>
            </div>

            <div className="space-y-3 max-h-[50vh] overflow-y-auto">
                {state.habits.filter(h => h.status === 'active').map(habit => {
                    const log = getLogForDate(selectedDate);
                    const isCompleted = log?.checks && log.checks[habit.id];

                    return (
                        <div key={habit.id} className="flex items-center justify-between py-2 border-b border-gray-100 dark:border-gray-800 last:border-0">
                            <span className="text-ledger-text dark:text-ledger-textDark">{habit.name}</span>
                            <div className="flex items-center gap-2">
                                {isCompleted ? (
                                    <>
                                        <span className="text-xs font-medium text-ledger-accent uppercase">Complete</span>
                                        <CheckCircle size={18} className="text-ledger-accent" />
                                    </>
                                ) : (
                                    <>
                                        <span className="text-xs font-medium text-ledger-muted uppercase">Missed</span>
                                        <XCircle size={18} className="text-ledger-muted" />
                                    </>
                                )}
                            </div>
                        </div>
                    );
                })}
                 {state.habits.filter(h => h.status === 'active').length === 0 && (
                     <p className="text-center text-ledger-muted py-4">No active habits tracked.</p>
                 )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import { 
  collection, 
  doc, 
  setDoc, 
  updateDoc, 
  serverTimestamp, 
  query, 
  getDocs, 
  writeBatch, 
  runTransaction,
  deleteDoc,
  deleteField,
  limit
} from "firebase/firestore";
import { db, auth } from "./firebase";
import { deleteUser } from "firebase/auth";

// --- HELPERS ---

export const getWeekId = (date: Date = new Date()): string => {
  // STRICT SUNDAY START
  const d = new Date(date);
  d.setHours(0,0,0,0);
  const day = d.getDay(); // 0 is Sunday
  // Rewind to Sunday
  d.setDate(d.getDate() - day);

  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const dayStr = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${dayStr}`;
};

export const getTodayStr = () => {
    const d = new Date();
    const offset = d.getTimezoneOffset() * 60000;
    const localISOTime = (new Date(d.getTime() - offset)).toISOString().slice(0, -1);
    return localISOTime.split('T')[0];
};

// --- TYPES ---

export interface FirestoreHabit {
  name: string;
  status: 'active' | 'archived';
  activeFrom: string;
  inactiveFrom: string | null;
  sortOrder: number;
  createdAt: any;
}

// --- CORE ACTIONS ---

// 0. Check if user has data (for onboarding)
export const checkUserHasHabits = async (userId: string): Promise<boolean> => {
    const habitsRef = collection(db, `users/${userId}/habits`);
    const q = query(habitsRef, limit(1));
    const snap = await getDocs(q);
    return !snap.empty;
};

// 1. Toggle Habit (Immediate - For Today)
export const toggleHabitCompletion = async (
  userId: string, 
  habitId: string, 
  dateStr: string
) => {
  const todayStr = getTodayStr();
  const weekId = getWeekId(new Date(dateStr));

  if (dateStr !== todayStr) throw new Error("Instant toggle only available for today.");

  const logRef = doc(db, `users/${userId}/dailyLogs`, dateStr);

  // Simple atomic toggle for today
  await runTransaction(db, async (transaction) => {
    const logSnap = await transaction.get(logRef);
    let currentChecks: Record<string, boolean> = {};
    if (logSnap.exists()) {
        currentChecks = logSnap.data().checks || {};
    }

    const isChecked = !!currentChecks[habitId];

    if (!isChecked) {
        transaction.set(logRef, {
            date: dateStr,
            weekId,
            checks: { [habitId]: true },
            updatedAt: serverTimestamp()
        }, { merge: true });
    } else {
        transaction.set(logRef, {
            checks: { [habitId]: deleteField() },
            updatedAt: serverTimestamp()
        }, { merge: true });
    }
  });
};

// 1b. Repair Past Day (Batch Update)
export const repairDailyLog = async (
    userId: string,
    dateStr: string,
    checks: Record<string, boolean>
) => {
    const weekId = getWeekId(new Date(dateStr));
    const logRef = doc(db, `users/${userId}/dailyLogs`, dateStr);
    const weekRef = doc(db, `users/${userId}/weeks`, weekId);

    await runTransaction(db, async (transaction) => {
        // A. Handle Repairs Token
        const weekSnap = await transaction.get(weekRef);
        let repairedDates: string[] = [];
        if (weekSnap.exists()) {
            repairedDates = weekSnap.data().repairedDates || [];
        }

        if (!repairedDates.includes(dateStr)) {
            if (repairedDates.length >= 3) {
                throw new Error("No repairs remaining this week.");
            }
            repairedDates.push(dateStr);
            transaction.set(weekRef, { 
                repairedDates, 
                updatedAt: serverTimestamp() 
            }, { merge: true });
        }

        // B. Update Log with full map provided
        transaction.set(logRef, {
            date: dateStr,
            weekId,
            checks, 
            updatedAt: serverTimestamp()
        }, { merge: true });
    });
};

// 2. Create Habit
export const createHabit = async (userId: string, name: string) => {
    const habitsRef = collection(db, `users/${userId}/habits`);
    const snapshot = await getDocs(habitsRef);
    const count = snapshot.size;

    const newDoc = doc(habitsRef);
    const todayStr = getTodayStr();

    await setDoc(newDoc, {
        name,
        status: 'active',
        activeFrom: todayStr,
        inactiveFrom: null,
        sortOrder: count,
        createdAt: serverTimestamp(),
        updatedAt: serverTimestamp()
    });
};

// 3. Rename Habit
export const renameHabit = async (userId: string, habitId: string, newName: string) => {
    const ref = doc(db, `users/${userId}/habits`, habitId);
    await updateDoc(ref, { 
        name: newName,
        updatedAt: serverTimestamp()
    });
};

// 4. Archive Habit
export const archiveHabit = async (userId: string, habitId: string) => {
    const ref = doc(db, `users/${userId}/habits`, habitId);
    const todayStr = getTodayStr();

    await updateDoc(ref, { 
        status: 'archived',
        inactiveFrom: todayStr,
        updatedAt: serverTimestamp()
    });
};

// 5. Reorder
export const reorderUserHabits = async (userId: string, orderedHabits: { id: string }[]) => {
    const batch = writeBatch(db);
    orderedHabits.forEach((h, index) => {
        const ref = doc(db, `users/${userId}/habits`, h.id);
        batch.update(ref, { sortOrder: index });
    });
    await batch.commit();
};

// 6. Delete User
export const deleteUserAccount = async (userId: string) => {
    const collections = ['habits', 'dailyLogs', 'weeks'];

    for (const colName of collections) {
        const colRef = collection(db, `users/${userId}/${colName}`);
        const snap = await getDocs(colRef);
        const batch = writeBatch(db);
        let counter = 0;

        for (const doc of snap.docs) {
            batch.delete(doc.ref);
            counter++;
            if (counter >= 400) { 
                await batch.commit();
                counter = 0;
            }
        }
        if (counter > 0) await batch.commit();
    }

    await deleteDoc(doc(db, 'users', userId));
    if (auth.currentUser) {
        await deleteUser(auth.currentUser);
    }
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { AppState, Habit, DailyLog, MAX_HABITS, STATIC_ACHIEVEMENTS, Achievement, ThemeOption } from '../types';
import { auth, db } from '../lib/firebase';
import { onAuthStateChanged, signOut } from 'firebase/auth';
import { 
    collection, 
    query, 
    orderBy, 
    onSnapshot, 
    doc, 
    getDoc, 
    getDocs,
    setDoc
} from 'firebase/firestore';
import { 
    getWeekId, 
    getTodayStr, 
    toggleHabitCompletion, 
    createHabit, 
    renameHabit, 
    archiveHabit, 
    FirestoreHabit,
    reorderUserHabits,
    deleteUserAccount,
    checkUserHasHabits,
    repairDailyLog
} from '../lib/firestore';

interface AppContextType {
  state: AppState;
  addHabit: (name: string) => void;
  toggleHabit: (habitId: string, date: string) => void;
  repairDay: (date: string, checks: Record<string, boolean>) => Promise<void>;
  checkHasHabits: () => Promise<boolean>;
  updateHabitName: (id: string, name: string) => void;
  archiveHabit: (id: string) => void;
  restoreHabit: (id: string) => void;
  reorderHabits: (fromIndex: number, toIndex: number) => void;
  completeOnboarding: () => void;
  setTheme: (theme: ThemeOption) => void;
  resetData: () => void;
  exportData: () => void;
  logOut: () => void;
  deleteAccount: () => void;
  stats: {
    currentStreak: number;
    totalLoggedDays: number;
    perfectDays: number;
    weeklyScore: number;
    getHabitConsistency: (habitId: string) => number;
  };
  isLoading: boolean;
}

const defaultState: AppState = {
  habits: [],
  logs: [],
  achievements: STATIC_ACHIEVEMENTS.map(a => ({ ...a })),
  isOnboarded: false,
  theme: 'dark',
  repairTokens: 3,
  dataYear: new Date().getFullYear(),
};

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);

  // Data State
  const [habits, setHabits] = useState<Habit[]>([]);
  const [logs, setLogs] = useState<DailyLog[]>([]);
  const [repairedDates, setRepairedDates] = useState<string[]>([]);
  const [userSettings, setUserSettings] = useState<{theme: ThemeOption, isOnboarded: boolean} | null>(null);

  // 1. Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (u) => {
      setUser(u);
      if (!u) {
        setHabits([]);
        setLogs([]);
        setUserSettings(null);
        setIsLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // 2. Data Listeners
  useEffect(() => {
    if (!user) return;

    const userId = user.uid;
    const currentWeekId = getWeekId();

    // A. Habits
    const habitsQuery = query(collection(db, `users/${userId}/habits`), orderBy('sortOrder'));
    const unsubHabits = onSnapshot(habitsQuery, (snapshot) => {
      const loadedHabits: Habit[] = snapshot.docs.map(d => {
        const data = d.data() as FirestoreHabit;
        return {
          id: d.id,
          name: data.name,
          status: data.status,
          activeFrom: data.activeFrom,
          inactiveFrom: data.inactiveFrom,
          sortOrder: data.sortOrder
        };
      });
      setHabits(loadedHabits);
    });

    // B. Logs
    // MVP: Load all. Optimization: Load only last 365 days or current view range.
    const logsQuery = query(collection(db, `users/${userId}/dailyLogs`)); 
    const unsubLogs = onSnapshot(logsQuery, (snapshot) => {
       const loadedLogs: DailyLog[] = snapshot.docs.map(d => ({
           id: d.id,
           ...d.data()
       })) as unknown as DailyLog[];
       setLogs(loadedLogs);
    });

    // C. User Settings
    const userRef = doc(db, `users`, userId);
    const unsubUser = onSnapshot(userRef, (docSnap) => {
        if(docSnap.exists()) {
            const data = docSnap.data();
            setUserSettings({
                theme: data.theme || 'dark',
                isOnboarded: data.isOnboarded || false
            });
            setIsLoading(false);
        } else {
            setDoc(userRef, { theme: 'dark', isOnboarded: false }, { merge: true });
            setIsLoading(false);
        }
    });

    // D. Week Summary (Repairs)
    const summaryRef = doc(db, `users/${userId}/weeks`, currentWeekId);
    const unsubSummary = onSnapshot(summaryRef, (docSnap) => {
        if(docSnap.exists()) {
            setRepairedDates(docSnap.data().repairedDates || []);
        } else {
            setRepairedDates([]);
        }
    });

    return () => {
      unsubHabits();
      unsubLogs();
      unsubUser();
      unsubSummary();
    };
  }, [user]);

  // --- ACTIONS ---

  const addHabit = async (name: string) => {
      if (!user) return;
      await createHabit(user.uid, name);
  };

  const toggleHabit = async (habitId: string, date: string) => {
      if (!user) return;
      try {
          await toggleHabitCompletion(user.uid, habitId, date);
      } catch (e: any) {
          throw e;
      }
  };

  const repairDay = async (date: string, checks: Record<string, boolean>) => {
      if (!user) return;
      await repairDailyLog(user.uid, date, checks);
  };

  const checkHasHabits = async () => {
      if (!user) return false;
      return await checkUserHasHabits(user.uid);
  };

  const updateHabitNameAction = async (id: string, name: string) => {
      if (!user) return;
      await renameHabit(user.uid, id, name);
  };

  const archiveHabitAction = async (id: string) => {
      if (!user) return;
      await archiveHabit(user.uid, id);
  };

  const restoreHabitAction = async (id: string) => {
      if (!user) return;
      // "Restore" creates a new habit with the same name to preserve history gaps
      const habit = habits.find(h => h.id === id);
      if (habit) {
          await createHabit(user.uid, habit.name);
      }
  };

  const reorderHabitsAction = async (fromIndex: number, toIndex: number) => {
      if (!user) return;
      const active = habits.filter(h => h.status === 'active');
      const moved = active[fromIndex];
      const newActive = [...active];
      newActive.splice(fromIndex, 1);
      newActive.splice(toIndex, 0, moved);
      await reorderUserHabits(user.uid, newActive);
  };

  const completeOnboarding = async () => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { isOnboarded: true }, { merge: true });
  };

  const setTheme = async (theme: ThemeOption) => {
      if (!user) return;
      const ref = doc(db, 'users', user.uid);
      await setDoc(ref, { theme }, { merge: true });
  };

  const logOut = async () => {
      await signOut(auth);
  };

  const resetData = async () => {
     await deleteAccountAction();
  };

  const deleteAccountAction = async () => {
      if (!user) return;
      try {
          await deleteUserAccount(user.uid);
          alert("Account deleted.");
      } catch(e) {
          console.error(e);
          alert("Error deleting account.");
      }
  };

  const exportData = () => {
      const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ habits, logs }));
      const downloadAnchorNode = document.createElement('a');
      downloadAnchorNode.setAttribute("href", dataStr);
      downloadAnchorNode.setAttribute("download", "ledger_export.json");
      document.body.appendChild(downloadAnchorNode);
      downloadAnchorNode.click();
      downloadAnchorNode.remove();
  };

  // --- THEME ---
  useEffect(() => {
    const html = document.documentElement;
    html.classList.remove(
      'dark', 'theme-dark', 'theme-vintage', 'theme-sepia', 
      'theme-cyberpunk', 'theme-nordic', 'theme-high-contrast', 
      'theme-zen', 'theme-oled', 'theme-blue-light'
    );
    const theme = userSettings?.theme || 'dark';
    if (theme !== 'light') {
        html.classList.add(`theme-${theme}`);
        html.classList.add('dark');
    } else {
        html.classList.remove('dark');
    }
  }, [userSettings?.theme]);

  // --- STATS CALCULATION ---
  const isHabitApplicable = (habit: Habit, date: string) => {
      if (date < habit.activeFrom) return false;
      if (habit.inactiveFrom && date >= habit.inactiveFrom) return false;
      return true;
  };

  const calculateStats = () => {
      const todayStr = getTodayStr();
      const currentWeekId = getWeekId();

      // Filter logs to those that have at least one check
      const validLogs = logs.filter(l => Object.keys(l.checks || {}).length > 0);
      const totalLoggedDays = validLogs.length;

      // Streak
      let currentStreak = 0;
      const sortedDates = validLogs.map(l => l.date).sort().reverse();
      if (sortedDates.length > 0) {
          const lastDate = new Date(sortedDates[0]);
          const today = new Date(todayStr);
          const diff = Math.floor((today.getTime() - lastDate.getTime()) / (1000 * 3600 * 24));
          if(diff <= 1) {
              currentStreak = 1;
              let prev = lastDate;
              for(let i=1; i<sortedDates.length; i++) {
                  const curr = new Date(sortedDates[i]);
                  const gap = Math.floor((prev.getTime() - curr.getTime()) / (1000 * 3600 * 24));
                  if(gap === 1) {
                      currentStreak++;
                      prev = curr;
                  } else break;
              }
          }
      }

      // Perfect Days & Weekly Score
      let perfectDays = 0;
      let totalWeekChecks = 0;
      let totalWeekPossible = 0;

      // We need to iterate dates for the current week to calculate weekly score precisely
      // Start of week
      const d = new Date();
      d.setHours(0,0,0,0);
      const day = d.getDay();
      d.setDate(d.getDate() - day); // Sunday

      for(let i=0; i<7; i++) {
          const dateStr = d.toISOString().split('T')[0];

          let dayPossible = 0;
          let dayChecks = 0;

          habits.forEach(h => {
              if (isHabitApplicable(h, dateStr)) {
                  dayPossible++;
                  const log = logs.find(l => l.date === dateStr);
                  if (log && log.checks && log.checks[h.id]) {
                      dayChecks++;
                  }
              }
          });

          totalWeekChecks += dayChecks;
          totalWeekPossible += dayPossible;
          d.setDate(d.getDate() + 1);
      }

      // Perfect Days (over all time)
      validLogs.forEach(log => {
          let dayPossible = 0;
          let dayChecks = 0;
          habits.forEach(h => {
              if(isHabitApplicable(h, log.date)) {
                  dayPossible++;
                  if(log.checks[h.id]) dayChecks++;
              }
          });
          if(dayPossible > 0 && dayChecks >= dayPossible) perfectDays++;
      });

      const weeklyScore = totalWeekPossible > 0 ? totalWeekChecks / totalWeekPossible : 0;

      return { currentStreak, totalLoggedDays, perfectDays, weeklyScore };
  };

  const state: AppState = {
      habits,
      logs,
      achievements: STATIC_ACHIEVEMENTS,
      isOnboarded: userSettings?.isOnboarded || false,
      theme: userSettings?.theme || 'dark',
      repairTokens: 3 - repairedDates.length,
      dataYear: new Date().getFullYear(),
  };

  return (
    <AppContext.Provider value={{ 
      state, 
      addHabit, 
      toggleHabit, 
      repairDay,
      checkHasHabits,
      updateHabitName: updateHabitNameAction, 
      archiveHabit: archiveHabitAction, 
      restoreHabit: restoreHabitAction, 
      reorderHabits: reorderHabitsAction, 
      completeOnboarding, 
      setTheme, 
      resetData, 
      exportData,
      logOut,
      deleteAccount: deleteAccountAction,
      stats: {
          ...calculateStats(),
          getHabitConsistency: (habitId) => {
              // Naive last 7 days consistency
              let checks = 0;
              const today = new Date();
              for(let i=0; i<7; i++) {
                 const d = new Date(today);
                 d.setDate(d.getDate() - i);
                 const ds = d.toISOString().split('T')[0];
                 const log = logs.find(l => l.date === ds);
                 if(log?.checks[habitId]) checks++;
              }
              return (checks / 7) * 100;
          }
      },
      isLoading
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (context === undefined) {
    throw new Error('useApp must be used within an AppProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff, CheckCircle2, ShieldCheck, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';

type Step = 'intro1' | 'intro2' | 'auth' | 'selection';

export const Onboarding: React.FC = () => {
  const { addHabit, completeOnboarding, checkHasHabits } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('intro1');

  // Selection State
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [resetMessage, setResetMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const finishSelection = () => {
      selected.forEach(habitName => addHabit(habitName));
      completeOnboarding();
      navigate('/today');
  };

  const handlePasswordReset = async () => {
    setAuthError('');
    setResetMessage('');
    if (!email) {
        setAuthError('Please enter your email address.');
        return;
    }

    setIsLoading(true);
    try {
        await sendPasswordResetEmail(auth, email);
        setResetMessage('Password reset email sent! Check your inbox.');
    } catch (error: any) {
        setAuthError(error.message);
    } finally {
        setIsLoading(false);
    }
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        let cred;
        if (isSignUp) {
            cred = await createUserWithEmailAndPassword(auth, email, password);
        } else {
            cred = await signInWithEmailAndPassword(auth, email, password);
        }

        // Auth Success. Check for habits.
        const userId = cred.user.uid;
        // Wait a small tick for context or just query directly. 
        // We use the helper from context which uses the newly authenticated user implicitly 
        // OR we can rely on the fact that 'user' state in AppContext updates via listener.
        // However, the listener is async. 
        // We should manually check firestore here using the known UID to be fast and synchronous in UI flow terms.

        if (isSignUp) {
             setStep('selection');
        } else {
             // For login, we will wait for the useEffect hook below to verify user habits.
        }
    } catch (error: any) {
        setAuthError(error.message);
        setIsLoading(false);
        return; // Stop here
    }

    // If we are here, we are authenticated but need to route.
    // If it was SignUp, we already setStep('selection').
    // If Login, we are waiting.
  };

  // Effect to handle post-login routing once User is available
  const { state: appState } = useApp(); // Access raw state to check user presence? 

  React.useEffect(() => {
      const verifyUser = async () => {
          if (auth.currentUser && step === 'auth' && !isLoading && !isSignUp) {
             // User is logged in, we are on auth step, not loading.
             setIsLoading(true);
             try {
                 const has = await checkHasHabits();
                 if (has) {
                     completeOnboarding();
                     navigate('/today');
                 } else {
                     setIsLoading(false);
                     setStep('selection');
                 }
             } catch (e) {
                 // If check fails, default to selection
                 setIsLoading(false);
                 setStep('selection');
             }
          }
      };

      if (auth.currentUser) {
           verifyUser();
      }
  }, [auth.currentUser, step, isSignUp, isLoading]);


  // --- VIEWS ---

  if (step === 'intro1') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
