            )}

            <div className="flex flex-wrap gap-2 mb-8">
                {DEFAULT_SUGGESTIONS.map(suggestion => (
                    <button
                        key={suggestion}
                        onClick={() => toggleSelection(suggestion)}
                        className={`px-4 py-2 rounded-full text-sm font-medium border transition-all ${selected.includes(suggestion) ? 'bg-ledger-accent text-white border-ledger-accent' : 'border-ledger-border dark:border-ledger-borderDark text-ledger-text dark:text-ledger-textDark'}`}
                    >
                        {suggestion}
                    </button>
                ))}
            </div>

            <div className="flex gap-2">
                <input 
                    type="text" 
                    value={customHabit}
                    onChange={(e) => setCustomHabit(e.target.value)}
                    placeholder="Custom habit..."
                    className="flex-1 bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent"
                    onKeyDown={(e) => e.key === 'Enter' && addCustom()}
                    maxLength={17}
                />
                <button onClick={addCustom} disabled={!customHabit} className="text-ledger-accent font-medium disabled:opacity-30">Add</button>
            </div>
        </div>
        <div className="absolute bottom-0 left-0 right-0 p-6 bg-gradient-to-t from-ledger-bg dark:from-ledger-bgDark to-transparent pt-12">
            <Button fullWidth onClick={finishSelection} disabled={selected.length === 0}>Complete Setup</Button>
        </div>
      </div>
    );
  }

  return null;
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { User, Check, Zap, X, AlertTriangle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { deleteField } from 'firebase/firestore'; // Import for type usage if needed, but we pass logic

export const Today: React.FC = () => {
  const { state, toggleHabit, repairDay } = useApp();
  const navigate = useNavigate();

  // Repair Modal State
  const [repairDate, setRepairDate] = useState<string | null>(null);
  const [repairChecks, setRepairChecks] = useState<Record<string, boolean>>({});
  const [isRepairing, setIsRepairing] = useState(false);

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const dayOfWeek = today.getDay();

  const startOfWeek = new Date(today);
  startOfWeek.setDate(today.getDate() - dayOfWeek);

  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);

  const weekDays = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(startOfWeek);
    d.setDate(startOfWeek.getDate() + i);
    return {
        dateStr: d.toISOString().split('T')[0],
        label: d.toLocaleDateString('en-US', { weekday: 'narrow' }),
        dayNum: d.getDate(),
        isToday: d.toISOString().split('T')[0] === todayStr,
        isFuture: d.toISOString().split('T')[0] > todayStr
    };
  });

  const displayHabits = state.habits.filter(h => h.status === 'active');

  // Stats Logic
  let totalCompleted = 0;
  let totalPotential = 0;

  displayHabits.forEach(h => {
      weekDays.forEach(day => {
          const isApplicable = day.dateStr >= h.activeFrom && (!h.inactiveFrom || day.dateStr < h.inactiveFrom);
          if (isApplicable) {
              totalPotential++;
              const log = state.logs.find(l => l.date === day.dateStr);
              if (log && log.checks && log.checks[h.id]) {
                  totalCompleted++;
              }
          }
      });
  });

  const weeklyPercentage = totalPotential > 0 ? (totalCompleted / totalPotential) * 100 : 0;

  const handleCellClick = (id: string, date: string, isFuture: boolean, isNA: boolean) => {
    if (isFuture || isNA) return;

    if (date === todayStr) {
        toggleHabit(id, date);
    } else {
        // Open Repair Modal
        openRepairModal(date);
    }
  };

  const openRepairModal = (date: string) => {
      // Init checks from existing log
      const log = state.logs.find(l => l.date === date);
      const currentChecks = log ? { ...log.checks } : {};
      setRepairChecks(currentChecks);
      setRepairDate(date);
  };

  const toggleRepairCheck = (habitId: string) => {
      setRepairChecks(prev => {
          const next = { ...prev };
          if (next[habitId]) {
              // We simulate deletion by setting false or removing key?
              // The `repairDailyLog` function needs to know what to delete.
              // In the Firestore function, we typically overwrite the map or use deleteField().
              // Simplest way: The passed map is the Source of Truth.
              // So if it's false/undefined here, it shouldn't exist in DB.
              // We'll clean it up before sending.
              delete next[habitId];
          } else {
              next[habitId] = true;
          }
          return next;
      });
  };

  const saveRepair = async () => {
      if (!repairDate) return;
      setIsRepairing(true);
      try {
          // Prepare the map.
          // Firestore `set(..., {merge: true})` merges top level fields. 
          // `checks` is a map field.
          // If we pass `checks: { a: true }`, it might merge with existing `{ b: true }` -> `{ a: true, b: true }`.
          // We want the result to be EXACTLY `repairChecks`.
          // To delete keys in a merge, we need `deleteField()`.

          const finalChecks: any = { ...repairChecks };

          // Find all habits applicable to that day
          const habitsForDay = state.habits.filter(h => 
             repairDate >= h.activeFrom && (!h.inactiveFrom || repairDate < h.inactiveFrom)
          );

          // For every applicable habit, if it's not in `repairChecks`, we explicitly delete it
          const { deleteField } = await import('firebase/firestore');

          habitsForDay.forEach(h => {
              if (!finalChecks[h.id]) {
                  finalChecks[h.id] = deleteField();
              }
          });

          await repairDay(repairDate, finalChecks);
          setRepairDate(null);
      } catch (e: any) {
          alert(e.message);
      } finally {
          setIsRepairing(false);
      }
  };

  return (
    <div className="flex flex-col h-full bg-ledger-bg dark:bg-ledger-bgDark relative font-sans">
      {/* Header */}
      <header className="px-6 py-5 flex items-center justify-between sticky top-0 z-50 bg-ledger-bg/95 dark:bg-ledger-bgDark/95 backdrop-blur-xl border-b border-ledger-border dark:border-ledger-borderDark">
        <div>
            <h1 className="text-base font-bold text-ledger-text dark:text-ledger-textDark tracking-tight">
                Current Week
            </h1>
            <p className="text-xs text-ledger-muted mt-0.5 font-medium">
                {startOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} – {endOfWeek.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
            </p>
        </div>
        <button onClick={() => navigate('/account')} className="p-2 -mr-2 text-ledger-text dark:text-ledger-textDark hover:opacity-70 transition-opacity">
          <User size={22} strokeWidth={2} />
        </button>
      </header>

      {/* KPI Section */}
      <div className="px-6 py-6 border-b border-ledger-border dark:border-ledger-borderDark bg-white dark:bg-[#111111]">
         <div className="flex items-center justify-between">
             <div>
                <div className="text-4xl font-extrabold text-ledger-text dark:text-ledger-textDark tracking-tight">
                    {Math.round(weeklyPercentage)}%
                </div>
                <div className="text-xs font-semibold text-ledger-muted uppercase tracking-wider mt-1">
                    {totalCompleted} / {totalPotential} Checks
                </div>
             </div>

             <div className="flex flex-col items-end gap-1">
                 <div className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 dark:bg-white/10 rounded-md">
                    <Zap size={14} className="text-ledger-accent" fill="currentColor" />
                    <span className="text-xs font-bold text-ledger-text dark:text-ledger-textDark">{state.repairTokens}</span>
                 </div>
                 <span className="text-[10px] font-medium text-ledger-muted">Repair Days Left</span>
             </div>
         </div>
      </div>

      {/* Main Grid */}
      <div className="flex-1 overflow-auto no-scrollbar pb-24 relative bg-ledger-bg dark:bg-ledger-bgDark">
         <table className="border-collapse min-w-full">
            <thead className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark shadow-sm">
                <tr>
                    <th className="sticky left-0 top-0 z-50 bg-ledger-bg dark:bg-ledger-bgDark border-b border-r border-gray-100 dark:border-gray-800 px-4 py-4 text-left">
                        <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider whitespace-nowrap">Task</span>
                    </th>
                    {weekDays.map(d => (
                        <th key={d.dateStr} className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark border-b border-gray-100 dark:border-gray-800 px-2 py-4 min-w-[60px]">
                            <div className={`flex flex-col items-center justify-center gap-1.5 ${d.isToday ? 'text-ledger-accent' : 'text-ledger-muted'}`}>
                                <span className="text-[10px] font-bold uppercase tracking-wider">{d.label}</span>
                                <span className={`text-xs font-bold w-6 h-6 flex items-center justify-center rounded-full transition-colors ${d.isToday ? 'bg-ledger-accent text-white shadow-md' : 'bg-transparent text-inherit'}`}>
                                    {d.dayNum}
                                </span>
                            </div>
                        </th>
                    ))}
                </tr>
            </thead>
            <tbody className="divide-y divide-gray-100 dark:divide-gray-800/50">
                {displayHabits.map(habit => (
                    <tr key={habit.id} className="group bg-white dark:bg-ledger-bgDark">
                        <td className="sticky left-0 z-30 bg-white dark:bg-ledger-bgDark border-r border-gray-100 dark:border-gray-800 px-4 py-3 whitespace-nowrap">
                            <span className="text-sm font-semibold text-ledger-text dark:text-ledger-textDark">
                                {habit.name}
                            </span>
                        </td>

                        {weekDays.map(d => {
                             const log = state.logs.find(l => l.date === d.dateStr);
                             const isCompleted = log?.checks && log.checks[habit.id];
                             const isApplicable = d.dateStr >= habit.activeFrom && (!habit.inactiveFrom || d.dateStr < habit.inactiveFrom);
                             const isNA = !isApplicable;

                             // Styles
                             let cellContent = null;
                             let cellClass = "w-10 h-10 rounded-lg flex items-center justify-center transition-all duration-200 border-2 mx-auto";

                             if (d.isFuture) {
                                 cellClass += " border-transparent bg-gray-50 dark:bg-white/5 opacity-30 cursor-not-allowed";
                             } else if (isNA) {
                                 cellClass += " border-transparent bg-gray-100 dark:bg-white/5 cursor-not-allowed";
                                 cellContent = <div className="w-4 h-0.5 bg-gray-300 dark:bg-gray-700 rounded-full" />;
                             } else if (isCompleted) {
                                 cellClass += " border-ledger-accent bg-ledger-accent text-white shadow-sm";
                                 cellContent = <Check size={20} strokeWidth={4} />;
                             } else {
                                 cellClass += " border-gray-200 dark:border-gray-800 bg-white dark:bg-ledger-surfaceDark hover:border-ledger-accent/50";
                             }

                            return (
                                <td key={d.dateStr} className="px-2 py-2">
                                     <button
                                        onClick={() => handleCellClick(habit.id, d.dateStr, d.isFuture, isNA)}
                                        disabled={d.isFuture || isNA}
                                        className="active:scale-95 transition-transform block w-full"
                                     >
                                         <div className={cellClass}>
                                             {cellContent}
                                         </div>
                                     </button>
                                </td>
                            );
                        })}
                    </tr>
                ))}
            </tbody>
         </table>
      </div>

      {/* REPAIR MODAL */}
      {repairDate && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setRepairDate(null)}>
            <div className="bg-white dark:bg-[#1A1A1A] rounded-2xl w-full max-w-sm overflow-hidden flex flex-col max-h-[80vh]" onClick={e => e.stopPropagation()}>
                <div className="p-6 border-b border-gray-100 dark:border-gray-800 flex justify-between items-center bg-gray-50 dark:bg-white/5">
                    <div>
                        <h3 className="text-lg font-bold text-ledger-text dark:text-ledger-textDark">Repair Day</h3>
                        <p className="text-sm text-ledger-muted">{new Date(repairDate).toLocaleDateString(undefined, { weekday: 'long', month: 'short', day: 'numeric'})}</p>
                    </div>
                    <button onClick={() => setRepairDate(null)} className="p-2 bg-gray-200 dark:bg-white/10 rounded-full">
                        <X size={18} />
                    </button>
                </div>

                <div className="p-4 overflow-y-auto flex-1 space-y-2">
                    {/* Only show habits applicable for that day */}
                    {state.habits.filter(h => repairDate >= h.activeFrom && (!h.inactiveFrom || repairDate < h.inactiveFrom)).map(h => (
                        <button 
                            key={h.id}
                            onClick={() => toggleRepairCheck(h.id)}
                            className={`w-full flex items-center justify-between p-4 rounded-xl border transition-all ${repairChecks[h.id] ? 'bg-ledger-accent text-white border-ledger-accent' : 'bg-transparent border-gray-200 dark:border-gray-700 text-ledger-text dark:text-ledger-textDark'}`}
                        >
                            <span className="font-semibold">{h.name}</span>
                            {repairChecks[h.id] ? <Check size={20} strokeWidth={3} /> : <div className="w-5 h-5 rounded-full border-2 border-gray-300 dark:border-gray-600" />}
                        </button>
                    ))}
                </div>

                <div className="p-4 bg-white dark:bg-[#1A1A1A] border-t border-gray-100 dark:border-gray-800">
                    <div className="flex items-center gap-2 mb-4 p-3 bg-amber-50 dark:bg-amber-900/10 rounded-lg text-amber-700 dark:text-amber-400 text-xs">
                         <AlertTriangle size={16} />
                         <span>Consumes 1 repair token (you have {state.repairTokens})</span>
                    </div>
                    <button 
                        onClick={saveRepair} 
                        disabled={isRepairing}
                        className="w-full h-12 bg-ledger-accent text-white font-bold rounded-xl flex items-center justify-center disabled:opacity-50"
                    >
                        {isRepairing ? 'Saving...' : 'Complete Repair'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../context/AppContext';
import { DEFAULT_SUGGESTIONS } from '../types';
import { Button } from '../components/Button';
import { X, ChevronLeft, Eye, EyeOff, CheckCircle2, Zap } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { auth } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, sendPasswordResetEmail } from 'firebase/auth';

type Step = 'intro1' | 'intro2' | 'auth' | 'selection';

export const Onboarding: React.FC = () => {
  const { addHabit, completeOnboarding, checkHasHabits } = useApp();
  const navigate = useNavigate();
  const [step, setStep] = useState<Step>('intro1');

  // Selection State
  const [selected, setSelected] = useState<string[]>([]);
  const [customHabit, setCustomHabit] = useState('');

  // Auth state
  const [isSignUp, setIsSignUp] = useState(false);
  const [isForgotPassword, setIsForgotPassword] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [authError, setAuthError] = useState('');
  const [resetMessage, setResetMessage] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const toggleSelection = (habit: string) => {
    if (selected.includes(habit)) {
      setSelected(prev => prev.filter(h => h !== habit));
    } else {
      setSelected(prev => [...prev, habit]);
    }
  };

  const addCustom = () => {
    if (!customHabit.trim()) return;
    setSelected(prev => [...prev, customHabit.trim()]);
    setCustomHabit('');
  };

  const finishSelection = () => {
      selected.forEach(habitName => addHabit(habitName));
      completeOnboarding();
      navigate('/today');
  };

  const handlePasswordReset = async () => {
    setAuthError('');
    setResetMessage('');
    if (!email) {
        setAuthError('Please enter your email address.');
        return;
    }

    setIsLoading(true);
    try {
        await sendPasswordResetEmail(auth, email);
        setResetMessage('Password reset email sent! Check your inbox.');
    } catch (error: any) {
        setAuthError(error.message);
    } finally {
        setIsLoading(false);
    }
  };

  const handleAuth = async () => {
    setAuthError('');
    if (!email || !password) {
        setAuthError('Please enter both email and password.');
        return;
    }

    setIsLoading(true);

    try {
        let cred;
        if (isSignUp) {
            cred = await createUserWithEmailAndPassword(auth, email, password);
            // New user via Sign Up -> Always go to Selection
            setIsLoading(false);
            setStep('selection');
        } else {
            cred = await signInWithEmailAndPassword(auth, email, password);
            // Existing user via Log In -> Check for data
            const hasHabits = await checkHasHabits();
            if (hasHabits) {
                // User has data, skip selection
                await completeOnboarding(); // Ensure flag is set in case it was missing
                navigate('/today');
            } else {
                // User has no data (empty account), show selection
                setIsLoading(false);
                setStep('selection');
            }
        }
    } catch (error: any) {
        setAuthError(error.message);
        setIsLoading(false);
    }
  };

  // --- VIEWS ---

  if (step === 'intro1') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in relative">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <div className="w-16 h-16 bg-ledger-accent rounded-2xl flex items-center justify-center mb-6 shadow-lg text-white">
                      <CheckCircle2 size={32} />
                  </div>
                  <h1 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-4">
                      Accountability, <br/> Simplified.
                  </h1>
                  <p className="text-ledger-muted text-lg max-w-xs">
                      No bells, no whistles. Just a serious tool to track what matters daily.
                  </p>
              </div>
              <div className="w-full">
                  <Button fullWidth onClick={() => setStep('intro2')}>Next</Button>
              </div>
          </div>
      );
  }

  if (step === 'intro2') {
      return (
          <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col items-center justify-center p-8 text-center animate-fade-in">
              <div className="flex-1 flex flex-col items-center justify-center">
                  <div className="w-16 h-16 bg-gray-200 dark:bg-[#262626] rounded-2xl flex items-center justify-center mb-6 shadow-sm text-ledger-text dark:text-ledger-textDark">
                      <Zap size={32} />
                  </div>
                  <h1 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-4">
                      3 Repair Days
                  </h1>
                  <p className="text-ledger-muted text-lg max-w-xs">
                      Life happens. You get 3 chances per week to fix past mistakes. Use them wisely.
                  </p>
              </div>
              <div className="w-full flex gap-3">
                   <Button variant="secondary" onClick={() => setStep('intro1')}>Back</Button>
                   <Button fullWidth onClick={() => setStep('auth')}>Get Started</Button>
              </div>
          </div>
      );
  }

  // Auth Step
  if (step === 'auth') {
    if (isForgotPassword) {
        return (
            <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
                <div className="mb-8 mt-2">
                    <button onClick={() => setIsForgotPassword(false)} className="flex items-center text-ledger-muted hover:text-ledger-text">
                        <ChevronLeft size={20} className="mr-1" /> Back
                    </button>
                </div>
                <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">Reset Password</h2>
                <div className="space-y-6 mt-6">
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" />
                    {authError && <p className="text-red-500 text-sm">{authError}</p>}
                    {resetMessage && <p className="text-green-500 text-sm">{resetMessage}</p>}
                    <Button fullWidth onClick={handlePasswordReset} disabled={isLoading}>{isLoading ? 'Sending...' : 'Send Link'}</Button>
                </div>
            </div>
        );
    }

    return (
      <div className="min-h-screen bg-ledger-bg dark:bg-ledger-bgDark p-6 flex flex-col max-w-md mx-auto animate-fade-in">
         <div className="mb-8 mt-2">
            <button onClick={() => setStep('intro2')} className="flex items-center text-ledger-muted hover:text-ledger-text">
                <ChevronLeft size={20} className="mr-1" /> Back
            </button>
         </div>

         <div className="flex-1 flex flex-col justify-center">
            <h2 className="text-2xl font-bold text-ledger-text dark:text-ledger-textDark mb-2">
              {isSignUp ? 'Create Account' : 'Welcome Back'}
            </h2>
            <p className="text-ledger-muted mb-8">Sync your data across devices.</p>

            <div className="space-y-6">
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted">Email</label>
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent" placeholder="you@example.com" />
                </div>
                <div>
                    <label className="text-xs font-bold uppercase text-ledger-muted">Password</label>
                    <div className="relative">
                        <input type={showPassword ? "text" : "password"} value={password} onChange={e => setPassword(e.target.value)} className="w-full bg-transparent border-b border-ledger-border dark:border-ledger-borderDark py-2 text-ledger-text dark:text-ledger-textDark focus:outline-none focus:border-ledger-accent pr-10" placeholder="••••••" onKeyDown={e => e.key === 'Enter' && handleAuth()} />
                        <button onClick={() => setShowPassword(!showPassword)} className="absolute right-0 top-2 text-ledger-muted">
                            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                        </button>
                    </div>
                </div>

                {!isSignUp && (
                    <div className="flex justify-end">
                        <button onClick={() => setIsForgotPassword(true)} className="text-xs text-ledger-muted hover:text-ledger-accent">Forgot Password?</button>
                    </div>
                )}
            </div>

            {authError && <div className="mt-4 p-3 bg-red-50 dark:bg-red-900/20 text-red-600 rounded-lg text-sm">{authError}</div>}

            <div className="mt-8 space-y-4">
                <Button fullWidth onClick={handleAuth} disabled={isLoading}>
                    {isLoading ? 'Processing...' : (isSignUp ? 'Sign Up' : 'Log In')}
                </Button>
                <button onClick={() => { setIsSignUp(!isSignUp); setAuthError(''); }} className="w-full text-center text-xs text-ledger-muted hover:text-ledger-text">
                    {isSignUp ? 'Already have an account? Log in' : "Don't have an account? Sign up"}
                </button>
            </div>
         </div>
      </div>
    );
  }

  // Selection Step
  if (step === 'selection') {
    return (
      <div className="h-full bg-ledger-bg dark:bg-ledger-bgDark flex flex-col max-w-md mx-auto relative animate-fade-in">
        <div className="flex-1 overflow-y-auto p-6 pb-24 no-scrollbar">
            <h2 className="text-3xl font-bold text-ledger-text dark:text-ledger-textDark mb-2 mt-8">
              Habit Selection
            </h2>
            <p className="text-ledger-muted text-base mb-8">
              Select habits to start your journey.
            </p>

            {selected.length > 0 && (
                <div className="mb-6 space-y-2">
