        })}

        {isAdding ? (
            <div className="flex items-center gap-2 p-4 bg-white dark:bg-ledger-surfaceDark rounded-xl border border-ledger-accent animate-fade-in">
                <input 
                    autoFocus
                    value={newHabitName}
