                        <span className="font-bold text-[10px] text-ledger-muted uppercase tracking-wider whitespace-nowrap">Task</span>
                    </th>
                    {weekDays.map(d => (
                        <th key={d.dateStr} className="sticky top-0 z-40 bg-ledger-bg dark:bg-ledger-bgDark border-b border-gray-100 dark:border-gray-800 px-2 py-4 min-w-[60px]">
