// --- HELPERS ---

export const getWeekId = (date: Date = new Date()): string => {
  // STRICT SUNDAY START
  const d = new Date(date);
  d.setHours(0,0,0,0);
  const day = d.getDay(); // 0 is Sunday
  // Rewind to Sunday
  d.setDate(d.getDate() - day);

  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const dayStr = String(d.getDate()).padStart(2, '0');
  return `${year}-${month}-${dayStr}`;
};

export const getTodayStr = () => {
    const d = new Date();
    const offset = d.getTimezoneOffset() * 60000;
    const localISOTime = (new Date(d.getTime() - offset)).toISOString().slice(0, -1);
    return localISOTime.split('T')[0];
};

export const getDateTs = (dateStr: string) => {
    // Create timestamp for midnight local time of that date string
    // Standardize to YYYY-MM-DD just in case
    const normalized = dateStr.replace(/\//g, '-');
    const d = new Date(normalized + 'T00:00:00'); 

    if (isNaN(d.getTime())) {
      console.error(`Invalid date string passed to getDateTs: ${dateStr}`);
      return Timestamp.now();
    }

    return Timestamp.fromDate(d);
};

// Canonicalize name: lowercase, remove all whitespace, remove punctuation/symbols
export const getCanonicalName = (name: string): string => {
    return name
        .toLowerCase()
        .replace(/[\s\p{P}\p{S}]/gu, ''); 
};

// --- TYPES ---

export interface FirestoreHabit {
  name: string;
  canonicalName: string;
  status: 'active' | 'archived';
  activeFrom: string;
  inactiveFrom: string | null;
  sortOrder: number;
  createdAt: any;
}

// --- CORE ACTIONS ---

// 0. Check if user has data (for onboarding)
export const checkUserHasHabits = async (userId: string): Promise<boolean> => {
    const habitsRef = collection(db, `users/${userId}/habits`);
    const q = query(habitsRef, limit(1));
    const snap = await getDocs(q);
    return !snap.empty;
};

// 1. Toggle Habit (Immediate - For Today)
export const toggleHabitCompletion = async (
  userId: string, 
  habitId: string, 
  dateStr: string
) => {
  const todayStr = getTodayStr();
  const weekId = getWeekId(new Date(dateStr));

  if (dateStr !== todayStr) throw new Error("Instant toggle only available for today. Use Repair for past dates.");

  const logRef = doc(db, `users/${userId}/logs`, dateStr);

  await runTransaction(db, async (transaction) => {
    const logSnap = await transaction.get(logRef);
    let currentChecks: Record<string, boolean> = {};
    if (logSnap.exists()) {
        currentChecks = logSnap.data().checks || {};
    }

    const isChecked = !!currentChecks[habitId];

    if (!isChecked) {
        transaction.set(logRef, {
            date: dateStr,
            dateTs: getDateTs(dateStr),
            weekId,
            checks: { [habitId]: true },
            updatedAt: serverTimestamp()
        }, { merge: true });
    } else {
        transaction.set(logRef, {
            checks: { [habitId]: deleteField() },
            updatedAt: serverTimestamp()
        }, { merge: true });
    }
  });
};

// 1b. Repair Past Day (Consumes Token per Edit)
export const repairDailyLog = async (
    userId: string,
    dateStr: string,
    checks: Record<string, boolean>
) => {
    const weekId = getWeekId(new Date(dateStr));
    const logRef = doc(db, `users/${userId}/logs`, dateStr);
    const weekRef = doc(db, `users/${userId}/weeks`, weekId);

    const validChecks: Record<string, boolean> = {};
    Object.entries(checks).forEach(([k, v]) => {
        if (v === true) validChecks[k] = true;
    });

    await runTransaction(db, async (transaction) => {
        // A. Handle Repairs Token (Action Based)
        const weekSnap = await transaction.get(weekRef);
        let repairsRemaining = 3; 

        if (weekSnap.exists()) {
            const data = weekSnap.data();
            // Default to 3 if field missing (backward compat or lazy creation)
            repairsRemaining = typeof data.repairsRemaining === 'number' ? data.repairsRemaining : 3;
        } else {
            // If week doc doesn't exist, we assume a fresh week with 3 tokens
            // We'll create it in the set operation below
            repairsRemaining = 3;
        }

        if (repairsRemaining <= 0) {
            throw new Error("No repair tokens remaining this week.");
        }

        // Decrement token
        const newRemaining = repairsRemaining - 1;

        // B. Update Week Doc
        transaction.set(weekRef, { 
            repairsRemaining: newRemaining,
            weekStartTs: getDateTs(weekId),
            updatedAt: serverTimestamp() 
        }, { merge: true });

        // C. Update Log
        transaction.set(logRef, {
            date: dateStr,
            dateTs: getDateTs(dateStr),
            weekId,
            checks: validChecks, 
            updatedAt: serverTimestamp()
        });
    });
};

// 2. Create Habit (Transactional with Uniqueness Check)
export const createHabit = async (userId: string, name: string) => {
    const canon = getCanonicalName(name);
    if (!canon) throw new Error("Invalid habit name.");

    const habitsRef = collection(db, `users/${userId}/habits`);
    const indexRef = doc(db, `users/${userId}/habitNameIndex`, canon);

    await runTransaction(db, async (transaction) => {
        // 1. Check uniqueness
        const indexSnap = await transaction.get(indexRef);
        if (indexSnap.exists()) {
            throw new Error(`Habit "${name}" already exists.`);
        }

        // 2. Get count for sort order AND limit check
        const snapshot = await getDocs(query(habitsRef)); 
        const activeCount = snapshot.docs.filter(d => d.data().status === 'active').length;

        if (activeCount >= 15) {
            throw new Error("Max 15 active habits allowed.");
        }

        const count = snapshot.size;
        const newHabitRef = doc(habitsRef);
        const todayStr = getTodayStr();

        // 3. Create Index
        transaction.set(indexRef, {
            habitId: newHabitRef.id,
            createdAt: serverTimestamp()
        });

        // 4. Create Habit
        transaction.set(newHabitRef, {
            name,
            canonicalName: canon,
            status: 'active',
            activeFrom: todayStr,
            inactiveFrom: null,
            sortOrder: count,
            createdAt: serverTimestamp(),
            updatedAt: serverTimestamp()
        });
    });
};

// 3. Rename Habit (Transactional with Swap)
export const renameHabit = async (userId: string, habitId: string, newName: string) => {
    const newCanon = getCanonicalName(newName);
    if (!newCanon) throw new Error("Invalid habit name.");

    const habitRef = doc(db, `users/${userId}/habits`, habitId);
    const newIndexRef = doc(db, `users/${userId}/habitNameIndex`, newCanon);

    await runTransaction(db, async (transaction) => {
        const habitSnap = await transaction.get(habitRef);
        if (!habitSnap.exists()) throw new Error("Habit not found.");

        const data = habitSnap.data() as FirestoreHabit;
        const oldCanon = data.canonicalName;

        if (oldCanon === newCanon) {
            // Case change or whitespace only change that results in same canonical
            transaction.update(habitRef, { 
                name: newName,
                updatedAt: serverTimestamp()
            });
            return;
        }

        // Check if new name is taken
        const newIndexSnap = await transaction.get(newIndexRef);
        if (newIndexSnap.exists()) {
            throw new Error(`Habit "${newName}" already exists.`);
        }

        // Delete old index
        const oldIndexRef = doc(db, `users/${userId}/habitNameIndex`, oldCanon);
        transaction.delete(oldIndexRef);

        // Create new index
        transaction.set(newIndexRef, {
            habitId,
            createdAt: serverTimestamp()
        });

        // Update habit
        transaction.update(habitRef, { 
            name: newName,
            canonicalName: newCanon,
            updatedAt: serverTimestamp()
        });
    });
};

// 4. Archive Habit
export const archiveHabit = async (userId: string, habitId: string) => {
    const ref = doc(db, `users/${userId}/habits`, habitId);
    const todayStr = getTodayStr();

    await updateDoc(ref, { 
        status: 'archived',
        inactiveFrom: todayStr,
        updatedAt: serverTimestamp()
    });
};

// 5. Reorder
export const reorderUserHabits = async (userId: string, orderedHabits: { id: string }[]) => {
    const batch = writeBatch(db);
    orderedHabits.forEach((h, index) => {
        const ref = doc(db, `users/${userId}/habits`, h.id);
        batch.update(ref, { sortOrder: index });
    });
    await batch.commit();
};

// 6. ATOMIC ONBOARDING COMMIT (REQ 2)
export const commitOnboarding = async (
    userId: string, 
    habitNames: string[],
    timezone: string
) => {
    const userRef = doc(db, 'users', userId);
    const todayStr = getTodayStr();
    const currentWeekId = getWeekId();
    const weekRef = doc(db, `users/${userId}/weeks`, currentWeekId);

    await runTransaction(db, async (transaction) => {
        // 1. Check idempotency
        const userSnap = await transaction.get(userRef);
        if (userSnap.exists() && userSnap.data().isOnboarded) {
            return; // Already onboarded
        }

        // 2. Validate names and prepare writes
        const uniqueNames = new Set<string>();
        const processedHabits: { name: string, canon: string, ref: DocumentReference, indexRef: DocumentReference }[] = [];

        for (const name of habitNames) {
            const canon = getCanonicalName(name);
            if (!canon || uniqueNames.has(canon)) continue; // Skip dups in selection
            uniqueNames.add(canon);

            const habitRef = doc(collection(db, `users/${userId}/habits`));
            const indexRef = doc(db, `users/${userId}/habitNameIndex`, canon);

            // Check collisions (skipped for onboarding to prevent crash)
            const indexSnap = await transaction.get(indexRef);
            if (indexSnap.exists()) {
                 continue;
            }

            processedHabits.push({ name, canon, ref: habitRef, indexRef });
        }

        // 3. Execute Writes

        // User Doc
        transaction.set(userRef, {
            isOnboarded: true,
            theme: 'dark', // default
            tz: timezone,
            createdAt: userSnap.exists() ? userSnap.data().createdAt : serverTimestamp(),
            onboardedAt: serverTimestamp()
        }, { merge: true });

        // Week Doc (Initialize 3 repairs)
        transaction.set(weekRef, {
            weekStartTs: getDateTs(currentWeekId),
            repairsRemaining: 3, // Start with 3 tokens
            updatedAt: serverTimestamp()
        }, { merge: true });

        // Habits & Indices
        processedHabits.forEach((h, index) => {
            transaction.set(h.indexRef, {
                habitId: h.ref.id,
                createdAt: serverTimestamp()
            });

            transaction.set(h.ref, {
                name: h.name,
                canonicalName: h.canon,
                status: 'active',
                activeFrom: todayStr,
                inactiveFrom: null,
                sortOrder: index,
                createdAt: serverTimestamp(),
                updatedAt: serverTimestamp()
            });
        });
    });
};

// 7. Delete User (Clean up Index)
export const deleteUserAccount = async (userId: string) => {
    const collections = ['habits', 'logs', 'weeks', 'habitNameIndex'];

    for (const colName of collections) {
        const colRef = collection(db, `users/${userId}/${colName}`);
        const snap = await getDocs(colRef);
        const batch = writeBatch(db);
        let counter = 0;

        for (const doc of snap.docs) {
            batch.delete(doc.ref);
            counter++;
            if (counter >= 400) { 
                await batch.commit();
                counter = 0;
            }
        }
        if (counter > 0) await batch.commit();
    }

    await deleteDoc(doc(db, 'users', userId));
    if (auth.currentUser) {
        await deleteUser(auth.currentUser);
    }
};

